output.rtl/priority_encoder.v:
module priority_encoder_8x3(
    input [7:0] in,
    output reg [2:0] out
);

    // Initialize output to 0
    always @ (in) begin
        out = 3'b000;
    end

    // Check for active input bit by bit from most significant to least
    always @ (in) begin
        if (in[7]) begin
            out = 3'b111;
        end else if (in[6]) begin
            out = 3'b110;
        end else if (in[5]) begin
            out = 3'b101;
        end else if (in[4]) begin
            out = 3'b011;
        end else if (in[3]) begin
            out = 3'b010;
        end else if (in[2]) begin
            out = 3'b001;
        end
    end

endmodule

input.rtl/priority_encoder.v:
module priority_encoder_8x3 (
    input       [7:0] in      ,   // 8 input lines
    output reg  [2:0] out         // 3 output lines
);

always @(*) begin
    if (in[7])
        out = 3'b111;
    else if (in[6])
        out = 3'b110;
    else if (in[5])
        out = 3'b101;
    else if (in[4])
        out = 3'b100;
    else if (in[3])
        out = 3'b011;
    else if (in[2])
        out = 3'b010;
    else if (in[1])
        out = 3'b001;
    else if (in[0])
        out = 3'b000;
    else
        out = 3'b000; // Default case when no inputs are active
end

endmodule

output.rtl/cascaded_encoder.v:
module cascaded_encoder #(parameter N = 8) (
    input_signal [N-1:0],
    output out [N/2-1:0],
    output out_upper_half [N/4-1:0],
    output out_lower_half [N/4-1:0]
);

    wire [N/4-1:0] in_upper_half [N/4-1:0];
    wire [N/4-1:0] in_lower_half [N/4-1:0];

    // Divide input_signal into upper and lower halves
    assign in_upper_half = input_signal[N/2-1:0];
    assign in_lower_half = input_signal[N/4-1:0];

    // Instantiate two parameterized priority encoders
    parameter M = N/2-1;
    priority_encoder #(M) encoder_upper (
        .input_signal(in_upper_half),
        .out(out)
    );

    parameter M = N/4-1;
    priority_encoder #(M) encoder_lower (
        .input_signal(in_lower_half),
        .out(out_lower_half)
    );

    // Determine which half has the first active input
    wire first_active_bit;
    assign first_active_bit = ((out !== out_lower_half) && (out !== out_upper_half)) ? 1'b1 : 1'b0;

    // Combine the outputs of the two encoders
    assign out = first_active_bit ? out_upper_half : out_lower_half;

endmodule

output.rtl/Attenuator.sv:
module Attenuator (
    input        clk,
    input        reset,
    input  [4:0] data,
    output reg   ATTN_CLK,
    output reg   ATTN_DATA,
    output reg   ATTN_LE
);

// Internal Signals
reg        clk_div2;
reg  [1:0] current_state, next_state;
reg  [4:0] shift_reg;
reg  [2:0] bit_count;
reg  [4:0] old_data;

// Parameters for FSM States
localparam IDLE  = 2'b00,
           LOAD  = 2'b01,
           SHIFT = 2'b10,
           LATCH = 2'b11;

// Reset Condition
always @(posedge clk or posedge reset) begin
    if (reset) begin
        clk_div2 <= 1'b0;
        current_state <= IDLE;
        ATTN_CLK      <= 1'b0;
        ATTN_DATA     <= 1'b0;
        ATTN_LE       <= 1'b0;
        shift_reg     <= 5'b00000;
        bit_count     <= 3'd0;
        old_data      <= 5'b00000;
    end else begin
        if (current_state == IDLE && data != old_data) begin
            current_state <= LOAD;
            shift_reg <= data;
            ATTN_CLK      <= 1'b1;
            bit_count      <= 5'd0;
            old_data       <= data;
        end else if (current_state == LOAD && bit_count == 5'd0) begin
            current_state <= SHIFT;
            bit_count <= bit_count + 1'b1;
        end else if (current_state == SHIFT && bit_count == 5'd0) begin
            ATTN_DATA <= shift_reg[bit_count];
            bit_count <= bit_count - 1'b1;
            ATTN_CLK      <= 1'b1;
        end else if (current_state == SHIFT && bit_count == 5'd0) begin
            current_state <= LATCH;
            ATTN_LE <= 1'b1;
            bit_count <= 3'd0;
        end else if (current_state == LATCH && bit_count == 5'd0) begin
            bit_count <= bit_count - 1'b1;
            ATTN_CLK      <= 1'b0;
            ATTN_LE       <= 1'b0;
        end
    end
end

endmodule

output.rtl/GP.v:
module GP (
    input i_A,
    input i_B,
    input i_Cin,
    output reg o_generate,
    output reg o_propagate,
    output reg o_Cout
);

    // Generate and Propagate outputs
    assign o_generate = i_A & i_B;
    assign o_propagate = i_A | i_B;

    // Carry-out computation
    always @ (i_A, i_B, i_Cin) begin
        if (i_A && i_B) begin
            o_Cout = i_Cin | o_generate;
        end else if (i_A || i_B) begin
            o_Cout = i_Cin | o_propagate;
        end else begin
            o_Cout = i_Cin;
        end
    end

endmodule

input.rtl/pipelined_adder_32bit.sv:
module pipelined_adder_32bit (
    input clk,       // Synchronous to posedge of clk 
    input reset,     // Synchronous active high reset
    input [31:0] A,  // 32 bit operand for addition  
    input [31:0] B,  // 32 bit operand for addition  
    input start,     // Active high signal to indicate when valid input data is provided
    output [31:0] S, // Final sum or result 
    output Co,       // Final carry out 
    output done      // Completion signal, active high when computation is complete    
);

    wire [7:0] A1, B1, A2, B2, A3, B3;
    wire carry1, carry2, carry3;
    wire [7:0] s13, s23, s12, A21, B21, A31, B31, A32, B32;
    wire [7:0] s1, s2, s3;
    wire control2, control1, control3, control4;

    dff #(1) FF00 (.clk(clk), .reset(reset), .D(1'b1), .Q(control1));

    dff #(8) FF11 (.clk(clk), .reset(reset), .D(A[15:8]), .Q(A1));
    dff #(8) FF12 (.clk(clk), .reset(reset), .D(B[15:8]), .Q(B1));
    dff #(8) FF13 (.clk(clk), .reset(reset), .D(A[23:16]), .Q(A2));
    dff #(8) FF14 (.clk(clk), .reset(reset), .D(B[23:16]), .Q(B2));
    dff #(8) FF15 (.clk(clk), .reset(reset), .D(A[31:24]), .Q(A3));
    dff #(8) FF16 (.clk(clk), .reset(reset), .D(B[31:24]), .Q(B3));

    carry_lookahead_adder #(8) ADD1 (.clk(clk), .reset(reset), .A(A[7:0]), .B(B[7:0]), .Cin(1'b0), .S(s1), .carry(carry1));

    dff #(1) FF01 (.clk(clk), .reset(reset), .D(control1), .Q(control2));

    dff #(8) FF21 (.clk(clk), .reset(reset), .D(s1), .Q(s12));
    dff #(8) FF23 (.clk(clk), .reset(reset), .D(A3), .Q(A21));
    dff #(8) FF24 (.clk(clk), .reset(reset), .D(B3), .Q(B21));
    dff #(8) FF25 (.clk(clk), .reset(reset), .D(A2), .Q(A31));
    dff #(8) FF26 (.clk(clk), .reset(reset), .D(B2), .Q(B31));

    carry_lookahead_adder #(8) ADD2 (.clk(clk), .reset(reset), .A(A1), .B(B1), .Cin(carry1), .S(s2), .carry(carry2));

    dff #(1) FF10 (.clk(clk), .reset(reset), .D(control2), .Q(control3));

    dff #(8) FF31 (.clk(clk), .reset(reset), .D(s2), .Q(s13));
    dff #(8) FF32 (.clk(clk), .reset(reset), .D(s12), .Q(s23));
    dff #(8) FF35 (.clk(clk), .reset(reset), .D(A31), .Q(A32));
    dff #(8) FF36 (.clk(clk), .reset(reset), .D(B31), .Q(B32));

    carry_lookahead_adder #(8) ADD3 (.clk(clk), .reset(reset), .A(A21), .B(B21), .Cin(carry2), .S(s3), .carry(carry3));

    dff #(1) FF111 (.clk(clk), .reset(reset), .D(control3), .Q(done));

    dff #(8) FF41 (.clk(clk), .reset(reset), .D(s13), .Q(S[7:0]));
    dff #(8) FF42 (.clk(clk), .reset(reset), .D(s23), .Q(S[15:8]));
    dff #(8) FF43 (.clk(clk), .reset(reset), .D(s3), .Q(S[23:16]));

    carry_lookahead_adder #(8) ADD4 (.clk(clk), .reset(reset), .A(A32), .B(B32), .Cin(carry3), .S(S[31:24]), .carry(Co));

endmodule

module carry_lookahead_adder #(parameter WIDTH = 32) (
    input [WIDTH-1:0] A,    // WIDTH bit operand for addition
    input [WIDTH-1:0] B,    // WIDTH bit operand for addition
    input Cin, clk, reset,  // Cin -> carry in, clk -> Synchronous to posedge of clk , reset -> Synchronous active high reset           
    output reg [WIDTH-1:0] S, // Final sum or result 
    output reg carry          // Final carry out           
);

    wire [WIDTH-1:0] P;
    wire [WIDTH-1:0] G;
    reg [WIDTH:0] C;

    wire [WIDTH-1:0] S1;
    wire carry1;

    // Generate (G) and Propagate (P) 
    genvar i;
    generate
        for (i = 0; i < WIDTH; i = i + 1) begin
            assign P[i] = A[i] ^ B[i];   
            assign G[i] = A[i] & B[i];   
        end
    endgenerate

    // Carry Calculation:
    generate
        for (i = 0; i < WIDTH; i = i + 1) begin
            always @(posedge clk) begin
                if (reset) begin
                    C <= 0; 
                end else begin
                    C[0] <= Cin;
                    C[i+1] <= G[i] | (P[i] & C[i]);
                end
            end
        end
    endgenerate

    // Final sum
    generate
        for (i = 0; i < WIDTH; i = i + 1) begin
            assign S1[i] = P[i] ^ C[i]; 
        end
    endgenerate

    // Final sum
    assign carry1 = C[WIDTH-1];

    always @(posedge clk) begin
        if (reset) begin
            S <= 0; 
            carry <= 0;   
        end else begin
            S <= S1; 
            carry <= carry1;
        end 
    end

