module glitch_free_mux
(
    input clk1,		//input clk1
    input clk2,		// input clk2
    input rst_n,	// async reset
    input sel,		// selection line
    output  clkout	// clock output
);

reg clkout_reg ;
reg clk1_enable, clk2_enable;
reg clk1_out, clk2_out ;


// CLK1 ENABLE LOGIC
always@(posedge clk1 or negedge rst_n  ) begin
        if (~rst_n) begin
            clk1_enable <= 0 ; 
        end else begin
            clk1_enable <= ~ clk2_enable & ~sel  ;
        end 
end

// CLK2 ENABLE LOGIC
always@(posedge clk2 or negedge rst_n  ) begin
       if (~rst_n) begin
           clk2_enable <= 0 ; 
       end else begin
           clk2_enable <= ~ clk1_enable & sel  ;
       end 
end

// OUTPUT LOGIC
assign clkout = (clk1 & clk1_enable) | (clk2 & clk2_enable) ;

endmodule

output.rtl/glitch_free_mux.sv:
module glitch_free_mux
(
    input clk1,		//input clk1
    input clk2,		// input clk2
    input rst_n,	// async reset
    input sel,		// selection line
    output  clkout	// clock output
);

// Two-flop clock synchronizers
reg clk1_sync_reg, clk1_sync_next;
reg clk2_sync_reg, clk2_sync_next;

always @(posedge clk1 or negedge rst_n) begin
    if (!rst_n) begin
        clk1_sync_reg <= 0;
        clk1_sync_next <= 0;
    end else begin
        clk1_sync_reg <= clk1_sync_next;
        clk1_sync_next <= clk1_reg ^ sel;
    end
end

always @(posedge clk2 or negedge rst_n) begin
    if (!rst_n) begin
        clk2_sync_reg <= 0;
        clk2_sync_next <= 0;
    end else begin
        clk2_sync_reg <= clk2_sync_next;
        clk2_sync_next <= clk2_reg ^ sel;
    end
end

reg clk1_reg, clk2_reg;

// Synchronize clk1
always @(posedge clk1_sync_reg or negedge rst_n) begin
    if (!rst_n) begin
        clk1_reg <= 0;
    end else begin
        clk1_reg <= clk1_sync_next;
    end
end

// Synchronize clk2
always @(posedge clk2_sync_reg or negedge rst_n) begin
    if (!rst_n) begin
        clk2_reg <= 0;
    end else begin
        clk2_reg <= clk2_sync_next;
    end
end

// OUTPUT LOGIC
assign clkout = (clk1 & clk1_reg) | (clk2 & clk2_reg);

endmodule

