            end
            1: begin
                // Addition mode
                if (pslverr) begin
                    prdata <= sram_memory[5];
                end else begin
                    prdata <= (sram_memory[r_operand_1] + sram_memory[r_operand_2]);
                end
            end
            2: begin
                // Multiplication mode
                if (pslverr) begin
                    prdata <= sram_memory[5];
                end else begin
                    prdata <= (sram_memory[r_operand_1] * sram_memory[r_operand_2]);
                end
            end
        endcase

