            r_operand_1 <= 0;
            r_operand_2 <= 0;
            r_Enable <= 0;
            r_write_address <= 0;
            r_write_data <= 0;
            pready <= 1'b0;
            prdata <= 8'b0;
            pslverr <= 1'b0;
        end
