    end

    always @(posedge clk or posedge reset_in) begin
        if (reset_in) begin
            rom <= 32'h0;
        end else begin
            rom[address_a] <= data_a;
            rom[address_b] <= data_b;
            rom[address_c] <= data_c;
        end
    end
endmodule

// ------------------------------------------------------------------
// DSP Processing Block
