output.rtl/axi_register.sv:
module axi_register (
    input wire clk,
    input wire rst_n,
    input wire [31:0] awaddr,
    input wire awvalid,
    input wire [31:0] wdata,
    input wire wvalid,
    input wire [7:0] wstrb,
    input wire bready,
    input wire [31:0] araddr,
    input wire arvalid,
    output reg rready,
    output reg [31:0] beat,
    output reg start,
    output reg done,
    output reg writeback,
    output reg [31:0] id
);

    // Internal signals
    reg [20:0] beat_counter;

    // Handshaking signals
    reg awready, wready;
    reg bresp, rresp;
    reg bvalid;

    // Register map
    reg [20:0] beat_reg;
    reg [31:0] id_reg;

    // State machine
    always @(posedge clk or posedge rst_n) begin
        if (rst_n) begin
            beat_counter <= 0;
            start <= 0;
            done <= 0;
            writeback <= 0;
            beat <= 0;
            id_reg <= 0;
        end else begin
            case (awvalid)
               1'b1: begin
                    if (awready) begin
                        // Address phase
                        awaddr_i = awaddr;
                        awready <= 0;

                        // Data phase
                        wdata_i = wdata;
                        wvalid_i = wvalid;
                        wready <= 0;

                        if (wvalid && wstrb) begin
                            // Full write
                            if (wdata[0] == 1'b1) begin
                                beat_counter <= wdata;
                                start <= 1'b1;
                                writeback <= 1'b1;
                                done <= 0;
                            end else begin
                                done <= 1'b1;
                                writeback <= 1'b0;
                            end
                        end else if (wvalid) begin
                            // Partial write
                            done <= 1'b0;
                        end
                    end
                end

               1'b1: begin
                    if (arready) begin
                        // Address phase
                        araddr_i = araddr;
                        arready <= 0;

                        // Data phase
                        if (arvalid) begin
                            // Read operation
                            rdata_o <= beat_counter;
                            rvalid_o <= 1'b1;
                            rready <= 1'b1;
                        end else begin
                            // Invalid address
                            rresp_o <= 1'b1;
                            rready <= 1'b0;
                        end
                    end
                end
            endcase
        end

        // Completion phase
        case ({awvalid, wvalid, arvalid})
           1'b11: begin
                bresp_o <= 2'b00;
                bvalid_o <= 1'b1;
            end
            1'b10: begin
                bresp_o <= 2'b10;
                bvalid_o <= 1'b1;
            end
            1'b01: begin
                bresp_o <= 2'b10;
                bvalid_o <= 1'b1;
            end
            1'b00: begin
                bresp_o <= 2'b00;
                bvalid_o <= 1'b1;
            end
        endcase
    end

    // ID register read-only
    always @(*) begin
        if (id_reg) begin
            id_reg <= 32'h0001_0001; // Fixed ID value
        end else begin
            id_reg <= 32'hzzzz_zzzz; // Default value for read-only registers
        end
    end

    // Reset functionality
    always @(rst_n) begin
        beat_counter <= 0;
        start <= 0;
        done <= 0;
        writeback <= 0;
        beat <= 0;
        id <= 32'hzzzz_zzzz; // Default value for registers
    end

endmodule

output.rtl/axis_resize.sv:
module axis_resize (

  input                                           clk,          //Global clock signal: Signals are sampled on the rising edge of clk
  input                                           resetn,       //The global reset signal: resetn is synchronous active-LOW reset.

  input                                           s_valid,      //The s_axis_valid signal indicates that the slave is driving a valid transfer.
  output  reg                                     s_ready,      //The s_axis_ready indicates that the slave can accept a transfer in the current cycle.
  input       [15:0]  s_data,                                   //The s_axis_data is the primary payload data from slave.

  output  reg                                     m_valid,      //The m_axis_valid indicates that the master is driving a valid transfer.
  input                                           m_ready,      //The m_axis_ready indicates that the slave can accept a transfer in the current cycle.
  output  reg [7:0] m_data                                      //The m_axis_data is the primary payload data to master.
);

  reg [15:0] temp_data;
  always @(posedge clk) begin
    if (resetn == 1'b0) begin
      temp_data <= 16'b0;
      s_ready <= 1'b0;
      m_valid <= 1'b0;
      m_data <= 8'b0;
    end else begin
      if (s_valid == 1'b1) begin
        temp_data <= s_data;
        s_ready <= 1'b1;
        m_valid <= 1'b1;
        m_data <= {temp_data[14:8], temp_data[7]};
      end
    end
  end

endmodule

output.rtl/axis_upscale.sv:
module axis_upscale(
    input clk,
    input resetn,
    input dfmt_enable,
    input dfmt_type,
    input dfmt_se,
    input s_axis_valid,
    input [23:0] s_axis_data,
    output reg m_axis_ready,
    output reg m_axis_valid,
    output [31:0] m_axis_data
);

    reg [31:0] m_axis_data_temp;

    always @(posedge clk) begin
        if (resetn) begin
            m_axis_ready <= 0;
            m_axis_valid <= 0;
            m_axis_data_temp <= 32'b0;
        end else begin
            if (dfmt_enable) begin
                if (dfmt_type) begin
                    m_axis_data_temp[23] = ~s_axis_data[23];
                end else begin
                    m_axis_data_temp[23] = s_axis_data[23];
                end
                if (dfmt_se) begin
                    m_axis_data_temp[22:0] = s_axis_data;
                end else begin
                    m_axis_data_temp[22:0] = 32'b0;
                end
            end else begin
                m_axis_data_temp = 32'b0;
            end

            m_axis_ready <= s_axis_valid;
            m_axis_valid <= 1;
            m_axis_data <= m_axis_data_temp;
        end
    end

endmodule

output.rtl/axi_tap.sv:
module axi_tap #(
    parameter ADDR_WIDTH = 32, // Width of AXI4-Lite Address
    parameter DATA_WIDTH = 32  // Width of AXI4-Lite Data
)(
    // Global Ports
    input           clk_i,
    input           rst_i,

    // Master Write Address Channel (AW)
    input           inport_awvalid_i,
    input  [ADDR_WIDTH-1:0]   inport_awaddr_i,
    output          inport_awready_o,
    // Master Write Data Channel (W)
    input           inport_wvalid_i,
    input  [DATA_WIDTH-1:0]   inport_wdata_i,
    input  [3:0]    inport_wstrb_i,
    output          inport_wready_o,
    // Master Write Response Channel (B)
    input           inport_bready_i,
    output          inport_bvalid_o,
    output [1:0]    inport_bresp_o,
    // Master Read Address Channel (AR)
    input           inport_arvalid_i,
    input  [ADDR_WIDTH-1:0]   inport_araddr_i,
    output          inport_arready_o,
    // Master Read Data Channel (R)
    input           inport_rready_i,
    output          inport_rvalid_o,
    output [DATA_WIDTH-1:0]   inport_rdata_o,
    output [1:0]    inport_rresp_o,

    // Default AXI outport
    // Write Address Channel (AW)
    input           outport_awready_i,
    output          outport_awvalid_o,
    output [`ADDR_WIDTH-1:0]   outport_awaddr_o,
    // Write Data Channel (W)
    input           outport_wready_i,
    output          outport_wvalid_o,
    output [DATA_WIDTH-1:0]   outport_wdata_o,
    output [3:0]    outport_wstrb_o,
    // Write Response Channel (B)
    input           outport_bvalid_i,
    input  [1:0]    outport_bresp_i,
    output          outport_bready_o,
    // Read Address Channel (AR)
    input           outport_arready_i,
    output          outport_arvalid_o,
    output [`ADDR_WIDTH-1:0]   outport_araddr_o,
    // Read Data Channel (R)
    input           outport_rvalid_i,
    input  [DATA_WIDTH-1:0]   outport_rdata_i,
    input  [1:0]    outport_rresp_i,
    output          outport_rready_o,

    // Peripheral 0 interface
