            if (axi_wvalid && axi_wready) begin
                temp_v <= axi_wdata;
                temp_wdata <= axi_wstrb;
            end
            if (axi_bvalid && axi_bready) begin
                axi_bresp <= temp_bresp;
            end
            if (axi_arvalid && axi_arready) begin
                temp_t <= slv_reg_t;
                temp_irq <= slv_reg_irq_mask;
                temp_v <= slv_reg_v;
                temp_ctl <= slv_reg_ctl;
