module binary_to_gray (
    parameter WIDTH = 6  // Define the bit width of the input
) (
    input  wire [WIDTH-1:0] binary_in,  // Binary input
    output wire [WIDTH-1:0] gray_out    // Gray code output
);

assign  gray_out[WIDTH-1] = binary_in[WIDTH-1];  // MSB is the same

generate
    for (genvar i = WIDTH-2; i > -1; i = i - 1) begin : xor_gen
        gray_out[i] = binary_in[i+1] ^ binary_in[i];
    end
endgenerate

endmodule

input.rtl/binary_to_gray.sv:
module binary_to_gray #(
    parameter WIDTH = 6
) (
    input  wire [WIDTH-1:0] binary_in,
    output wire [WIDTH-1:0] gray_out
);

  logic gray_out_d1;  

  assign gray_out[WIDTH-1] = binary_in[WIDTH-1];

  generate
    genvar i;
    for (i = 0; i < WIDTH - 1; i = i + 1) begin
      assign gray_out[i] = binary_in[i+1] ^ binary_in[i];
    end
  endgenerate

  always_ff @(posedge binary_in[0]) begin  
    gray_out = binary_in;  
  end

endmodule

