module bus_arbiter (
    input wire reset,
    input wire clk,
    input wire req1,
    input wire req2,
    output reg grant1,
    output reg grant2
);
    // State encoding using localparam
    localparam IDLE    = 3'b000,
               GRANT_1 = 3'b001,
               GRANT_2 = 3'b010,
               CLEAR   = 3'b011;

    // State registers
    reg [2:0] state;
    reg [2:0] next_state;

    // Sequential logic for state transition
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            state <= IDLE;
            grant1 <= 1'b0;
            grant2 <= 1'b0;
        end else begin
            state <= next_state;
        end
    end

    // Combinational logic for next state
    always @(*) begin
        // Default assignments
        next_state = state;

        case (state)
            IDLE:
                if (req1) begin
                    next_state = GRANT_1;
                end else if (req2) begin
                    next_state = GRANT_2;
                end else begin
                    next_state = IDLE;
                end
            GRANT_1:
                if (!req1) begin
                    next_state = CLEAR;
                end else begin
                    next_state = IDLE;
                end
            GRANT_2:
                if (!req2) begin
                    next_state = CLEAR;
                end else if (req1) begin
                    next_state = IDLE;
                end else begin
                    next_state = GRANT_2;
                end
            CLEAR:
                if (req1 || req2) begin
                    next_state = IDLE;
                end else begin
                    next_state = IDLE;
                end
        endcase
    end

    // Output logic
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            grant1 <= 1'b0;
            grant2 <= 1'b0;
        end else begin
            // Grant assignments based on next_state
            case (next_state)
                GRANT_1:
                    grant1 <= 1'b1;
                    grant2 <= 1'b0;
                GRANT_2:
                    grant1 <= 1'b0;
                    grant2 <= 1'b1;
                CLEAR:
                    grant1 <= 1'b0;
                    grant2 <= 1'b0;
                IDLE:
                    grant1 <= 1'b0;
                    grant2 <= 1'b0;
            endcase
        end
    end

endmodule

input.rtl/cvdp_copilot_bus_arbiter.sv:
module cvdp_copilot_bus_arbiter (
    input reset,
    input clk,
    input req1,
    input req2,
    output reg grant1,
    output reg grant2
    );

// State Encoding
localparam IDLE        = 3'b000,
            GRANT_1     = 3'b001,
            GRANT_2     = 3'b010,
            MASTER1_PRI = 3'b011,
            CLEAR       = 3'b100;

// STATE REGISTERS
reg [2:0] state;      // Current state
reg [2:0] next_state; // Next state

// State Transition
always @(posedge clk or posedge reset)
begin
    if (reset)
        state <= IDLE;
    else
        state <= next_state;
end

// Next State Logic
always @(*) begin
    next_state = state; // Default assignment
    case (state)
        IDLE: begin
            if (req2)
                next_state = GRANT_2;
            else if (req1)
                next_state = GRANT_1;
        end
        GRANT_2: begin
            if (!req2 && !req1)
                next_state = IDLE; // Both requests deasserted
            else if (!req2 && req1)
                next_state = GRANT_1; // Switch to GRANT_1 if req1 is still asserted
        end
        GRANT_1: begin
            if (!req1 && !req2)
                next_state = IDLE; // Both requests deasserted
            else if (req2)
                next_state = GRANT_2; // req2 has priority
        end
        MASTER1_PRI: begin
            if (req2)
                next_state = GRANT_2; // Grant Master 2 if req2 is asserted
            else if (req1)
                next_state = GRANT_1; // Grant Master 1 if only req1 is asserted
            else
                next_state = IDLE; // No requests, transition to IDLE
        end
        CLEAR: begin
            if (req2)
                next_state = GRANT_2;
            else if (req1)
                next_state = GRANT_1;
            else
                next_state = IDLE; // Default to IDLE if no requests
        end
        default: next_state = IDLE;
    endcase
end

// Output Logic
always @(posedge clk or posedge reset) begin
    if (reset) begin
        grant1 <= 1'b0;
        grant2 <= 1'b0;
    end else begin
        case (next_state)
            IDLE: begin
                grant1 <= 1'b0;
                grant2 <= 1'b0;
            end
            GRANT_1: begin
                grant1 <= 1'b1;
                grant2 <= 1'b0;
            end
            GRANT_2: begin
                grant1 <= 1'b0;
                grant2 <= 1'b1;
            end
            MASTER1_PRI: begin
                grant1 <= 1'b0; // During this state, neither master is granted
                grant2 <= 1'b0;
            end
            CLEAR: begin
                grant1 <= 1'b0;
                grant2 <= 1'b0;
            end
        endcase
    end
end

endmodule

output.rtl/cvdp_copilot_bus_arbiter.sv:
module cvdp_copilot_bus_arbiter (
    input reset,
    input clk,
    input req1,
    input req2,
    input dynamic_priority,
    output reg grant1,
    output reg grant2
    );

// State Encoding
localparam IDLE        = 3'b000,
            GRANT_1     = 3'b001,
            GRANT_2     = 3'b010,
            MASTER1_PRI = 3'b011,
            CLEAR       = 3'b100;

// State Registries
reg [2:0] state;      // Current state
reg [2:0] next_state; // Next state

// State Transition
always @(posedge clk or posedge reset)
begin
    if (reset)
        state <= IDLE;
    else
        state <= next_state;
end

// Next State Logic
always @(*) begin
    next_state = state; // Default assignment
    case (state)
        IDLE: begin
            if (dynamic_priority)
                next_state = GRANT_1;
            else
                next_state = IDLE;
        end
        GRANT_1: begin
            if (!dynamic_priority && !req2)
                next_state = IDLE; // No dynamic priority and req2 deasserted
            else if (!dynamic_priority && req2)
                next_state = GRANT_2; // req2 has priority
            else
                next_state = IDLE; // Dynamic priority is low, and req1 is still asserted
        end
        GRANT_2: begin
            if (!dynamic_priority && !req1)
                next_state = IDLE; // No dynamic priority and req1 deasserted
            else if (!dynamic_priority && req1)
                next_state = GRANT_1; // req1 has priority
            else
                next_state = IDLE; // Dynamic priority is low, and no requests
        end
        MASTER1_PRI: begin
            if (dynamic_priority)
                next_state = GRANT_1; // Dynamic priority grants priority to req1
            else
                next_state = IDLE; // No dynamic priority
        end
        CLEAR: begin
            if (dynamic_priority)
                next_state = GRANT_1;
            else
                next_state = IDLE;
        end
        default: next_state = IDLE;
    endcase
end

// Output Logic
always @(posedge clk or posedge reset) begin
    if (reset) begin
        grant1 <= 1'b0;
        grant2 <= 1'b0;
    end else begin
        case (next_state)
            IDLE: begin
                grant1 <= 1'b0;
                grant2 <= 1'b0;
            end
            GRANT_1: begin
                grant1 <= 1'b1;
                grant2 <= 1'b0;
            end
            GRANT_2: begin
                grant1 <= 1'b0;
                grant2 <= 1'b1;
            end
            MASTER1_PRI: begin
                grant1 <= 1'b0; // During this state, neither master is granted
                grant2 <= 1'b0;
            end
            CLEAR: begin
                grant1 <= 1'b0;
                grant2 <= 1'b0;
            end
        endcase
    end
end

endmodule

output.rtl/pseudo_lru_nmru_policy.sv:
module pseudo_lru_nmru_policy #(
    NWAYS = 4,
    NINDEXES = 32
) (
    input clock,
    input reset,
    input [$clog2(NINDEXES)-1:0] index,
    input [$clog2(NWAYS)-1:0] way_select,
    input access,
    input hit,
    output reg [$clog2(NWAYS)-1:0] way_replace
);

reg [NWAYS-1:0] recency [NINDEXES-1:0];

integer reset_counter;
always_ff @ (posedge clock or posedge reset) begin
    if (reset) begin
        for (reset_counter = 0; reset_counter < NINDEXES; reset_counter = reset_counter + 1) begin
            recency[reset_counter] <= {NWAYS{1'b0}};
        end
    end else begin
        if (access) begin
            recency[index] <= {way_select{1'b1}, recency[index] - 1'b1};
        end

        if (hit) begin
            recency[index] <= {1'b1, recency[index]};
        end

        if (recency[index] == {NWAYS{1'b0}}) begin
            way_replace = way_select;
            recency[index] <= {NWAYS{1'b0}};
        end else if (recency[index].count(1'b0) > 1) begin
            // NMRU policy
            int smallest_zero_index = NINDEXES;
            for (int i = 0; i < NINDEXES; i++) begin
                if (recency[i] == {NWAYS{1'b0}}) begin
                    smallest_zero_index = i;
                    break;
                end
            end
            way_replace = way_select[smallest_zero_index];
        end else begin
            // LRU policy
            way_replace = recency[index];
            recency[index] <= {1'b1, recency[index]};
        end
    end
end

endmodule : pseudo_lru_nmru_policy

output.rtl/lru_counter_policy.sv:
module lru_counter_policy #(
    parameter NWAYS = 4,
    parameter NINDEXES = 32
)(
    input clock,
    input reset,
    input [$clog2(NINDEXES)-1:0] index,
    input [$clog2(NWAYS)-1:0] way_select,
    input access,
    input hit,
    output [$clog2(NWAYS)-1:0] way_replace
);

    reg [(NWAYS * $clog2(NWAYS))-1:0] recency [NINDEXES-1:0];

    wire [$clog2(NWAYS)-1:0] lru_slot;

    integer i, n;

    // Recency Update Logic
    always_ff @ (posedge clock or posedge reset) begin
        if (reset) begin
            for (i = 0; i < NINDEXES; i = i + 1) begin
                for (n = 0; n < NWAYS; n = n + 1) begin
                    recency[i][(n * $clog2(NWAYS)) +: $clog2(NWAYS)] <= $clog2(NWAYS)'(n);
                end
            end
        end else begin
            // Cache hit: Update the accessed way and decrement other counters
            if (access) begin
                // Set the accessed way's counter to the maximum value
                recency[index][way_select] <= NWAYS - 1;
                // Decrement counters with a value greater than the previous value
                for (n = 0; n < NWAYS; n = n + 1) begin
                    if (recency[index][(n * $clog2(NWAYS)) +: $clog2(NWAYS)] > recency[index][way_select]) begin
                        recency[index][(n * $clog2(NWAYS)) +: $clog2(NWAYS)] <= recency[index][way_select] - 1;
                    end
                end
            end

            // LRU Replacement Logic
            // Find the least recently used way for replacement
            assign lru_slot = 0;
            assign way_replace = 0;
            for (i = 0; i < NINDEXES; i = i + 1) begin
                for (n = 0; n < NWAYS; n = n + 1) begin
                    if (recency[i][(n * $clog2(NWAYS)) +: $clog2(NWAYS)] < lru_slot) begin
                        lru_slot = recency[i][(n * $clog2(NWAYS)) +: $clog2(NWAYS)];
                        way_replace = n;
                    end
                end
            end
        end
    end

endmodule : lru_counter_policy

output.rtl/mru_counter_policy.sv:
module mru_counter_policy #(
    parameter NWAYS = 4,
    parameter NINDEXES = 32
)(
    input clock,
    input reset,
    input [$clog2(NINDEXES)-1:0] index,
    input [$clog2(NWAYS)-1:0] way_select,
    input access,
    input hit,
    output [$clog2(NWAYS)-1:0] way_replace
);

    reg [(NWAYS * $clog2(NWAYS))-1:0] recency [NINDEXES-1:0];

    wire [$clog2(NWAYS)-1:0] mru_slot;

    integer i, n;

    // Initialize recency array on reset
    always_ff @ (posedge clock or posedge reset) begin
        if (reset) begin
            for (i = 0; i < NINDEXES; i = i + 1) begin
                for (n = 0; n < NWAYS; n = n + 1) begin
                    recency[i][(n * $clog2(NWAYS)) +: $clog2(NWAYS)] <= $clog2(NWAYS)'(n);
                end
            end
        end
    end

    // Hit logic: update recency array and select MRU slot
    always_comb begin
        if (access && hit) begin
            recency[index][way_select] <= NWAYS - 1; // Set the accessed way as most recently used
            mru_slot = NWAYS - 1;
            for (n = 0; n < NWAYS; n = n + 1) begin
                if (n < way_select) begin
                    recency[index][(n * $clog2(NWAYS)) +: $clog2(NWAYS)] <= recency[index][(n * $clog2(NWAYS)) +: $clog2(NWAYS)] - 1;
                end
            end
        end
    end

    // Replacement logic: determine MRU slot for replacement
    always_comb begin
        mru_slot = -1;
        for (i = 0; i < NINDEXES; i = i + 1) begin
            for (n = 0; n < NWAYS; n = n + 1) begin
                if (recency[i][(n * $clog2(NWAYS)) +: $clog2(NWAYS)] > mru_slot) begin
                    mru_slot = recency[i][(n * $clog2(NWAYS)) +: $clog2(NWAYS)];
                end
            end
        end
    end

    assign way_replace = mru_slot;

endmodule : mru_counter_policy

output.rtl/lfu_counter_policy.sv:
module lfu_counter_policy #(
    parameter NWAYS = 4,
    parameter NINDEXES = 32,
    parameter COUNTERW = 2
)(
    input clock,
    input reset,
    input [$clog2(NINDEXES)-1:0] index,
    input [$clog2(NWAYS)-1:0] way_select,
    input access,
    input hit,
    output [$clog2(NWAYS)-1:0] way_replace
);

    localparam int unsigned MAX_FREQUENCY = $pow(2, COUNTERW) - 1;

    // Frequency array to track next way to be replaced
    reg [(NWAYS * COUNTERW)-1:0] frequency [NINDEXES-1:0];

    integer i, n;

    // Sequential logic for reset and frequency updates
    always_ff @ (posedge clock or posedge reset) begin
        if (reset) begin
            for (i = 0; i < NINDEXES; i = i + 1) begin
                for (n = 0; n < NWAYS; n = n + 1) begin
                    frequency[i][(n * COUNTERW) +: COUNTERW] <= COUNTERW'(0);
                end
            end
        end else begin
            if (access) begin
                // Increment the frequency counter of the accessed way
                if (hit) begin
                    if (frequency[index][(way_select * COUNTERW) +: COUNTERW] < MAX_FREQUENCY) begin
                        frequency[index][(way_select * COUNTERW) +: COUNTERW] <= frequency[index][(way_select * COUNTERW) +: COUNTERW] + 1;
                    end else begin
                        // Decrement the counters of the other ways
                        for (n = 0; n < NWAYS; n = n + 1) begin
                            if (n != way_select) begin
                                frequency[index][(n * COUNTERW) +: COUNTERW] <= frequency[index][(n * COUNTERW) +: COUNTERW] - 1;
                            end
                        end
                    end
                end else begin
                    // Replace the way with the least frequently used counter
                    way_replace <= 0;
                    for (n = 0; n < NWAYS; n = n + 1) begin
                        if (frequency[index][(n * COUNTERW) +: COUNTERW] < frequency[index][(way_select * COUNTERW) +: COUNTERW]) begin
                            way_replace <= n;
                            break;
                        end
                    end
                    // Set the counter of the replaced way to 1
                    if (way_replace != 0) begin
                        frequency[index][(way_replace * COUNTERW) +: COUNTERW] <= 1;
                    end
                end
            end
        end
    end

endmodule : lfu_counter_policy

output.rtl/pseudo_lru_tree_policy.sv:
module pseudo_lru_tree_policy #(
    parameter NWAYS = 4,
    parameter NINDEXES = 32
)(
    input clock,
    input reset,
    input [$clog2(NINDEXES)-1:0] index,
    input [$clog2(NWAYS)-1:0] way_select,
    input access,
    input hit,
    output [$clog2(NWAYS)-1:0] way_replace
);

    localparam int unsigned NBITS_TREE = NWAYS - 1;

    reg [NBITS_TREE-1:0] recency [NINDEXES-1:0];
    wire [NBITS_TREE-1:0] recency_updated;
    wire [$clog2(NWAYS)-1:0] pseudo_lru_slot;

    integer i;

    // Recency array update logic for hit
    always_ff @ (posedge clock or posedge reset) begin
        if (reset) begin
            for (i = 0; i < NINDEXES; i++) begin
                recency[i] <= NBITS_TREE'(0);
            end
        end else if (access) begin
            // Mark the selected way as most recently used
            recency[index] <= recency[index] ^ way_select;
            recency_updated = recency[index];
        end
    end

    // Select the Pseudo LRU slot
    slot_select_pseudo_lru_tree #(
        .NWAYS (NWAYS)
    ) slot_select_unit (
        .array (recency[index]),
        .index (pseudo_lru_slot)
    );

    assign way_replace = pseudo_lru_slot;

endmodule : pseudo_lru_tree_policy

module slot_select_pseudo_lru_tree #(
    parameter NWAYS = 4
)(
    input [NWAYS-2:0] array,
    output logic [$clog2(NWAYS)-1:0] index
);

    localparam int unsigned MAX_DEPTH = $clog2(NWAYS);

    integer depth;
    logic [$clog2(NWAYS)-1:0] step;
    logic direction;

    // Pseudo LRU slot selection logic
    always_comb begin
        direction = 1; // Traverse the tree
        index = array;
        depth = MAX_DEPTH;

        // Traverse the tree from the most recently used way
        while (direction && depth > 0) begin
            if (step == 0) begin
                index = index << 1; // Move to left child
                step = MAX_DEPTH - 1;
            end else begin
                index = index >> 1; // Move to right child
                step = step - 1;
            end
            depth = depth - 1;
        end
    end

endmodule : slot_select_pseudo_lru_tree

