module cascaded_adder #(
    parameter IN_DATA_WIDTH = 16,
    parameter IN_DATA_NS = 4
) (
    input clk,
    input rst_n,
    input i_valid,
    input [IN_DATA_WIDTH * IN_DATA_NS - 1:0] i_data,
    output reg o_valid,
    output [IN_DATA_WIDTH + $clog2(IN_DATA_NS) - 1:0] o_data
);

    reg [IN_DATA_WIDTH - 1:0] temp_sum;
    reg [IN_DATA_WIDTH - 1:0] stage_sum;

    always_ff @(posedge clk or posedge rst_n) begin
        if (rst_n) begin
            temp_sum <= 0;
            stage_sum <= 0;
            o_valid <= 0;
        end else if (i_valid) begin
            temp_sum <= i_data;
            stage_sum <= temp_sum;
            o_valid <= 1;
        end else begin
            o_valid <= 0;
        end
    end

    always_comb begin
        if (o_valid) begin
            o_data <= {stage_sum, temp_sum};
        end
    end

endmodule

module cascaded_adder #(
    parameter int IN_DATA_WIDTH = 16,                       // Width of each input data
    parameter int IN_DATA_NS = 4,                           // Number of input data elements
    parameter int NUM_STAGES = $clog2(IN_DATA_NS),          // Number of summation stages (calculated once)
    parameter logic [NUM_STAGES-1:0] REG = {NUM_STAGES{1'b1}}  // Control bits for register insertion
) (
   input  logic clk,
   input  logic rst_n,
   input  logic i_valid, 
   input  logic [IN_DATA_WIDTH*IN_DATA_NS-1:0] i_data,  // Flattened input data array
   output logic o_valid,
   output logic [(IN_DATA_WIDTH+$clog2(IN_DATA_NS))-1:0] o_data // Output data (sum)
);

   // Internal signals for the adder tree
   logic [IN_DATA_WIDTH*IN_DATA_NS-1:0] i_data_ff;                             // Flattened input data array register
   logic [IN_DATA_WIDTH-1:0] in_data_2d [IN_DATA_NS-1:0];                      // Intermediate 2D array
   logic [(IN_DATA_WIDTH+$clog2(IN_DATA_NS))-1:0] stage_output [NUM_STAGES-1:0][IN_DATA_NS>>1-1:0];
   logic valid_ff;
   logic valid_pipeline [NUM_STAGES-1:0];  // Pipeline to handle the valid signal latencies based on REG

   // Register the input data on valid signal
   always_ff @(posedge clk or negedge rst_n) begin : reg_indata
      if(!rst_n)
         i_data_ff <= 0;
      else begin
         if(i_valid) begin
            i_data_ff <= i_data;
         end
      end
   end

   // Convert flattened input to 2D array
   always_comb begin
       for (int i = 0; i < IN_DATA_NS; i++) begin : conv_1d_to_2d
           in_data_2d[i] = i_data_ff[(i+1)*IN_DATA_WIDTH-1 -: IN_DATA_WIDTH];
       end
   end

   // Generate the adder tree with register insertion based on REG
   genvar i, j;
   generate
       for (i = 0; i < NUM_STAGES; i++) begin : adder_gen
           if (REG[i]) begin
               always_comb begin
                   for (j = 0; j < IN_DATA_NS/2; j += 2) begin
                       stage_output[i][j] = in_data_2d[j] + in_data_2d[j+1];
                   end
               end
           end
       end
   endgenerate

   // Valid signal propagation with latency based on REG
   always_ff @(posedge clk or negedge rst_n) begin
      if(!rst_n)
         valid_ff <= 1'b0;
      else begin
         if(i_valid) begin
            if (REG[NUM_STAGES-1]) begin
               valid_pipeline[NUM_STAGES-1] <= valid_ff;
            end else begin
               valid_pipeline[NUM_STAGES-2] <= valid_ff;
            end
         end
      end
   end

   // Assign the final stage of valid_pipeline to o_valid
   always_ff @(posedge clk or negedge rst_n) begin
      if(!rst_n)
         o_valid <= 1'b0;
      else
         o_valid <= valid_pipeline[NUM_STAGES-1];
   end

   // Output data assignment
   always_ff @(posedge clk or negedge rst_n) begin
      if ( !rst_n) begin
         o_data <= 0 ;
      end else if (valid_pipeline[NUM_STAGES-1]) begin
         o_data <= stage_output[NUM_STAGES-1][0];
      end
   end

endmodule

input.rtl/cdc_pulse_synchronizer.sv:
module cdc_pulse_synchronizer (
    input  logic src_clock,   // Source Clock Domain
    input  logic des_clock,   // Destination Clock Domain
    input  logic rst_in,      // Reset
    input  logic src_pulse,   // Source Pulse
    output logic des_pulse    // Destination Pulse
);

    logic pls_toggle;      
    logic pls_toggle_synca;
    logic pls_toggle_syncc;

    //--------------------------------------------------
    //   Toggle Flop Circuit
    //---------------------------------------------------

    always_ff @(posedge src_clock or posedge rst_in) begin
        if (rst_in) begin
            pls_toggle <= 1'b0;
        end else if (src_pulse) begin
            pls_toggle <= ~pls_toggle;
        end else begin
            pls_toggle <= 1'b0;
        end
    end

    //--------------------------------------------------
    //   Double Flop Bit Synchronizer
    //---------------------------------------------------

    always_ff @(posedge des_clock or posedge rst_in) begin
        if (rst_in) begin
            pls_toggle_synca <= 1'b0;
        end else begin
            pls_toggle_synca <= pls_toggle;
        end
    end

    //--------------------------------------------------
    //   Delay Logic of Output signal
    //---------------------------------------------------

    always_ff @(posedge des_clock or posedge rst_in) begin
        if (rst_in) begin
            pls_toggle_syncc <= 1'b0;
        end else begin
            pls_toggle_syncc <= pls_toggle_synca;
        end
    end

    //--------------------------------------------------
    //   Assign Statement for posedge and negedge detection
    //---------------------------------------------------

    assign des_pulse = pls_toggle_syncc ^ pls_toggle_synca; 
endmodule

