            q[6]  <= CA_out[6];
            q[5]  <= CA_out[5];
            q[4]  <= CA_out[4];
            q[3]  <= CA_out[3];
            q[2]  <= CA_out[2];
            q[1]  <= CA_out[1];
            q[0]  <= CA_out[0];
        end
    end

