module data_width_converter(
    input clk,
    input reset,
    input [31:0] data_in,
    input data_valid,
    output reg [127:0] o_data_out,
    output reg o_data_out_valid
);

    // Internal state and counter
    reg [3:0] count;
    reg [127:0] buffer[4:0];

    // Reset condition
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            count <= 0;
            o_data_out <= 16'h0000000000000000;
            o_data_out_valid <= 0;
            for (int i = 0; i < 5; i++) begin
                buffer[i] <= 0;
            end
        end else begin
            if (count < 4) begin
                count <= count + 1;
                buffer[count] <= data_in;
                if (data_valid) begin
                    o_data_out_valid <= 1;
                    if (count == 4) begin
                        o_data_out <= {buffer[0], buffer[1], buffer[2], buffer[3]};
                        o_data_out_valid <= 0;
                        count <= 0;
                    end
                end
            end
        end
    end

endmodule

output.rtl/dbi_enc.sv:
module dbi_enc(
    input  [39:0] data_in,
    input  clk,
    input  rst_n,
    output reg [39:0] data_out,
    output reg [1:0] dbi_cntrl
);

    reg [20:0] prev_group1, prev_group0;

    // Initialization on reset
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            data_out <= 40'h00_0000_0000;
            dbi_cntrl <= 2'b00;
            prev_group1 <= 20'h0000_0000;
            prev_group0 <= 20'h0000_0000;
        end else begin
            prev_group1 <= prev_group1;
            prev_group0 <= prev_group0;
        end
    end

    // Comparison and output logic
    always @(posedge clk) begin
        if (!rst_n) begin
            prev_group1 <= 20'h0000_0000;
            prev_group0 <= 20'h0000_0000;
        end else begin
            if (data_in[39:20] != prev_group1) begin
                dbi_cntrl[1] = data_in[39:20] != prev_group1;
            end
            if (data_in[19:0] != prev_group0) begin
                dbi_cntrl[0] = data_in[19:0] != prev_group0;
            end

            prev_group1 <= data_in[39:20];
            prev_group0 <= data_in[19:0];

            case (dbi_cntrl)
                2'b01: data_out[39:20] = ~data_in[39:20];
                2'b10: data_out[19:0] = ~data_in[19:0];
                default: data_out = data_in;
            endcase
        end
    end

endmodule

output.rtl/dbi_dec.sv:
module dbi_dec (
   // Inputs
   input  wire        rst_n,     // Asynchronous reset
   input  wire        clk,       // Clock
   input  wire [39:0] data_in,   // Data input before DBI decoder logic
   input  wire [1:0]  dbi_cntrl, // Indicate data inversion enabled for each group 
   // Outputs
   output wire [39:0] data_out   // Output data after DBI logic
   );

   // Internal wires
   reg [39:0] group_1, group_0;

   // Splitting incoming data into two groups
   assign group_1 = {data_in[38:0], data_in[39:1]};
   assign group_0 = {data_in[28:0], data_in[39:2]};

   // Decoding each group based on dbi_cntrl
   always @(posedge clk or negedge rst_n) begin
       if (!rst_n) begin
           group_1 <= 40'h0000_0000;
           group_0 <= 40'h0000_0000;
       end else begin
           case (dbi_cntrl)
              2'b00: group_1 <= group_1;
              2'b01: group_1 <= ~group_1;
              2'b10: group_0 <= group_0;
              2'b11: group_0 <= ~group_0;
               default: group_1 <= 40'h0000_0000;
               group_0 <= 40'h0000_0000;
           endcase
       end
   end

   // Combining decoded groups to form the output
   assign data_out = {group_1, group_0};

endmodule

output.rtl/cvdp_copilot_decode_firstbit.sv:
module first_bit_decoder #(
    parameter int InWidth_g = 32,
    parameter logic InReg_g = 1,
    parameter logic OutReg_g = 1,
    parameter logic PlRegs_g
) (
    input logic clk,
    input logic rst,
    input logic [InWidth_g-1:0] in_data,
    input logic in_valid,
    output logic [$clog2(InWidth_g)-1:0] out_first_bit,
    output logic out_found,
    output logic out_valid
);

    // Internal signals
    logic [$clog2(InWidth_g)-1:0] stage_data [PlRegs_g-1:0];
    logic found, valid;

    // Internal always block
    always_ff @(posedge clk or posedge rst) begin
        if (rst) begin
            stage_data <= {InWidth_g{1'b0}};
            out_found <= 0;
            out_valid <= 0;
        end else begin
            if (in_valid) begin
                stage_data <= {stage_data[PlRegs_g-2:0], in_data};
                found <= stage_data[PlRegs_g-1];
                valid <= found;

                if (found) begin
                    out_first_bit <= $clog2(InWidth_g) - PlRegs_g + 1;
                    out_found <= 1;
                    out_valid <= 1;
                end
            end
        end
    end

    // Outputs
    assign out_first_bit = (PlRegs_g == 0) ? $clog2(InWidth_g) - 1 : out_first_bit;
    assign out_found = found;
    assign out_valid = valid & (PlRegs_g == 0) ? 1'b1 : out_valid;

endmodule

