module digital_dice_roller (
    input clk,
    input reset_n,
    input button,
    output reg [2:0] dice_value
);

    // State encoding
    typedef enum'(u[1:2]'({1'b0, 1'b1})) state_t;
    typedef enum'(u[1:2]'({1'b0, 1'b1})) next_state_t;

    // State register
    reg [1:0] state_reg;

    // Counter
    reg [2:0] counter;

    // State transition logic
    always @(posedge clk or posedge reset_n) begin
        if (reset_n) begin
            state_reg <= 3'b000;
            counter <= 3'b000;
            dice_value <= 3'b000;
        end else begin
            case (state_reg)
                3'b000: begin
                    if (button)
                        state_reg <= 3'b001;
                    else
                        state_reg <= 3'b000;
                    dice_value <= 3'b000;
                    counter <= 3'b001;
                end
                3'b001: begin
                    if (counter == 3'b110)
                        state_reg <= 3'b000;
                    else
                        counter <= counter + 1'b1;
                    dice_value <= counter;
                end
            endcase
        end
    end

    // State flip logic
    always @(posedge clk) begin
        state_reg <= state_reg + 1'b1;
        if (state_reg > 3'b110)
            state_reg <= 3'b000;
    end

endmodule

input.rtl/digital_dice_roller.sv:
module digital_dice_roller #(
    parameter int DICE_MAX  = 6,                    // Maximum dice value
    parameter int BIT_WIDTH = $clog2(DICE_MAX) + 1  // Bit width to represent dice value
) (
    input wire clk,
    input wire reset,  // Asynchronous reset signal
    input wire button,
    output reg [BIT_WIDTH-1:0] dice_value
);

  // State encoding
  typedef enum logic [1:0] {
    IDLE    = 2'b00,
    ROLLING = 2'b01
  } state_t;

  state_t current_state, next_state;
  reg [BIT_WIDTH-1:0] counter;  // Counter to represent dice values

  // State transition and asynchronous reset logic (sequential)
  always_ff @(posedge clk or negedge reset) begin
    if (!reset) begin
      // Reset to initial values when async_reset is asserted
      current_state <= IDLE;
      counter <= 1;
      dice_value <= 1;
    end else begin
      current_state <= next_state;
    end
  end

  // Next state logic and counter increment (combinational)
  always_comb begin
    next_state = current_state;

    case (current_state)
      IDLE: begin
        if (button) next_state = ROLLING;
      end

      ROLLING: begin
        if (!button) next_state = IDLE;
      end
    endcase
  end

  // Counter logic to simulate rolling dice values from 1 to DICE_MAX
  always_ff @(posedge clk or negedge reset) begin
    if (!reset) begin
      // Reset counter and dice value when async_reset is asserted
      counter <= 1;
      dice_value <= 1;
    end else if (current_state == ROLLING) begin
      if (counter == DICE_MAX) counter <= 1;  // Reset to 1 after reaching DICE_MAX
      else counter <= counter + 1;
    end else if (current_state == IDLE) begin
      dice_value <= counter;  // Latch the final value
    end
  end
endmodule

output.rtl/digital_dice_roller.sv:
module digital_dice_roller #(
    parameter int DICE_MAX  = 6,                    // Maximum dice value
    parameter int BIT_WIDTH = $clog2(DICE_MAX) + 1  // Bit width to represent dice value
) (
    input wire clk,
    input wire reset,  // Asynchronous reset signal
    input wire button,
    output reg [(NUM_DICE-1)*BIT_WIDTH-1:0] dice_values
);

  // State encoding
  typedef enum logic [(NUM_DICE-1):0] {
    IDLE = {2'b00, 2'b00, ... (NUM_DICE-2 times)}, // All dice in idle state
    ROLLING = {2'b01, 2'b01, ... (NUM_DICE-1 times)} // All dice in rolling state
  } state_t;

  state_t current_state, next_state;
  reg [(NUM_DICE-1)*BIT_WIDTH-1:0] counter;  // Counter to represent dice values

  // State transition and asynchronous reset logic (sequential)
  always_ff @(posedge clk or negedge reset) begin
    if (!reset) begin
      // Reset to initial values when async_reset is asserted
      current_state <= IDLE;
      for (int i = 0; i < NUM_DICE; i++) begin
        counter[i*(BIT_WIDTH-1)+:BIT_WIDTH-1] <= 1;
      end
      dice_values <= {counter[(NUM_DICE-1)*(BIT_WIDTH-1)-1:0], counter[(NUM_DICE-2)*(BIT_WIDTH-1)-1:0], ... (NUM_DICE-1 times)};
    end else begin
      current_state <= next_state;
    end
  end

  // Next state logic and counter increment (combinational)
  always_comb begin
    next_state = current_state;

    case (current_state)
      IDLE: begin
        if (button) next_state = ROLLING;
      end

      ROLLING: begin
        if (!button) next_state = IDLE;
      end
    endcase
