            // Reset behavior
            if (reset) begin
                TEMP_LOW = 0x0a;
                TEMP_MED = 0x0b;
                TEMP_HIGH = 0x0c;
                temp_adc_in_data = 0;
                fan_pwm_duty_cycle = 0;
                pready = 0;
                pslverr = 0;
            end
        end
    endcase
