module fsm_seq_detector (
    input bit clk_in,
    input bit rst_in,
    input bit seq_in,
    output reg seq_detected
);

    logic [2:0] cur_state, next_state;

    // State enumeration
    typedef enum logic [2:0] {
        S0, S1, S2, S3, S4, S5, S6, S7
    } state_t;

    // Initial state
    initial cur_state = S0;

    // State transition logic
    always_comb begin
        case (cur_state)
            S0: next_state = seq_in ? S1 : S0;
            S1: next_state = seq_in ? S2 : S0;
            S2: next_state = seq_in ? S3 : S0;
            S3: next_state = seq_in ? S4 : S0;
            S4: next_state = seq_in ? S5 : S0;
            S5: next_state = seq_in ? S6 : S0;
            S6: next_state = seq_in ? S7 : S0;
            S7: next_state = seq_in ? S0 : S0;
        endcase
    end

    // State register
    always_ff @(posedge clk_in or posedge rst_in) begin
        if (rst_in) begin
            cur_state <= S0;
            seq_detected <= 0;
        end else begin
            cur_state <= next_state;
        end
    end

    // Output logic
    always_comb begin
        if (cur_state == S7) begin
            seq_detected <= ~seq_detected; // Toggle output on detection
        end
    end

endmodule

input.rtl/fsm_seq_detector.sv:
module fsm_seq_detector
(
    input  bit     clk_in,       // Free Running Clock
    input  logic   rst_in,       // Active HIGH reset
    input  logic   seq_in,       // Continuous 1-bit Sequence Input
    output logic   seq_detected  // '0': Not Detected. '1': Detected. Will be HIGH for 1 Clock cycle Only
);

typedef enum logic [2:0] {S0, S1, S2, S3, S4, S5, S6, S7} state_t;
state_t cur_state, next_state;

logic seq_detected_w;

always @ (posedge clk_in or posedge rst_in)
begin
    if (rst_in)
        cur_state <= S0;
    else
        cur_state <= next_state;
end

always_comb begin
    if (rst_in) begin
        seq_detected_w = 1'b0;
        next_state = S0;
    end
    else begin
        case (cur_state)
            S0: begin
                if (seq_in) begin
                    next_state = S1;
                    seq_detected_w = 1'b0;
                end
                else begin
                    seq_detected_w = 1'b0;
                    next_state = S0;
                end	
            end
            S1: begin
                if (seq_in) begin
                    next_state = S1;
                    seq_detected_w = 1'b0;
                end
                else begin
                    next_state = S2;
                    seq_detected_w = 1'b0;
                end
            end
            S2: begin
                if (seq_in) begin
                    next_state = S3;
                    seq_detected_w = 1'b0;
                end
                else begin
                    next_state = S0;
                    seq_detected_w = 1'b0;
                end
            end
            S3: begin
                if (seq_in) begin
                    next_state = S4;
                    seq_detected_w = 1'b0;
                end
                else begin
                    next_state = S2;
                    seq_detected_w = 1'b0;
                end
            end
            S4: begin
                if (seq_in) begin
                    next_state = S1;
                    seq_detected_w = 1'b0;
                end
                else begin
