      .clk               (clk),
      .rst               (rst),
      .go                (go),
      .equal             (equal),
      .controlpath_state (controlpath_state),
      .done              (done)
   );

   gcd_datapath #( .WIDTH(WIDTH) ) dp_inst (
      .clk               (clk),
      .rst               (rst),
      .A                 (A),
      .B                 (B),
      .controlpath_state (controlpath_state),
      .equal             (equal),
      .OUT               (OUT)
   );

