  input  logic   [(IN_ROW*IN_COL*DATA_WIDTH)-1:0] image_in,           // Flattened input image
  output logic                                    valid_out,          // Indicates valid output image
  output logic [(OUT_ROW*OUT_COL*DATA_WIDTH)-1:0] image_out           // Flattened output image
);

  logic [(OUT_ROW*OUT_COL*DATA_WIDTH)-1:0] padded_image, padded_image_reg;     // Padded image stored in registers
  logic [(OUT_ROW*OUT_COL*DATA_WIDTH)-1:0] transposed_image, transposed_image_reg; // Transposed image stored in registers
  logic [(OUT_ROW*OUT_COL*DATA_WIDTH)-1:0] rotated_image, rotated_image_reg;    // Final rotated image (latency buffer)

  logic [5:0] valid_out_reg;

  // Optimized Step 1: Pad the input image into a square image
  always_ff @(posedge clk) begin
    if (srst) begin
      padded_image <= '0;
      transposed_image <= '0;
    end else begin
      for (int pad_row = 0; pad_row < OUT_ROW; pad_row++) begin
        for (int pad_col = 0; pad_col < OUT_COL; pad_col++) begin
          if ((pad_row < IN_ROW) && (pad_col < IN_COL)) begin
            // Copy input data into padded_image
            padded_image[(pad_row * OUT_COL + pad_col) * DATA_WIDTH +: DATA_WIDTH] <= image_in[(pad_row * IN_COL + pad_col) * DATA_WIDTH +: DATA_WIDTH];
          end else begin
            // Fill remaining positions with zeros
            padded_image[(pad_row * OUT_COL + pad_col) * DATA_WIDTH +: DATA_WIDTH] <= '0;
          end
        end
      end
      // Transpose padded image in one step
      transposed_image <= padded_image_reg;
    end
  end

  always_ff @(posedge clk) begin
    padded_image_reg <= padded_image;
    transposed_image_reg <= transposed_image;
  end

  // Optimized Step 3: Apply rotation logic with additional latency buffer
  // Rotate the transposed image directly without intermediate storage
  always_ff @(posedge clk) begin
    if (srst) begin
      rotated_image <= '0;
    end else begin
      for (int rot_row = 0; rot_row < OUT_ROW; rot_row++) begin
        for (int rot_col = 0; rot_col < OUT_COL; rot_col++) begin
          case (rotation_angle)
            // 90° Clockwise: Transpose + Reverse Rows
            2'b00: rotated_image[(rot_row * OUT_COL + rot_col) * DATA_WIDTH +: DATA_WIDTH] <= transposed_image_reg[(OUT_ROW-1-rot_row) * OUT_COL + rot_col] * DATA_WIDTH;

            // 180° Clockwise: Reverse Rows and Columns
            2'b01: rotated_image[(rot_row * OUT_COL + rot_col) * DATA_WIDTH +: DATA_WIDTH] <= transposed_image_reg[(OUT_ROW-1-rot_row) * OUT_COL + (OUT_COL-1-rot_col)] * DATA_WIDTH;

            // 270° Clockwise: Transpose + Reverse Columns
            2'b10: rotated_image[(rot_row * OUT_COL + rot_col) * DATA_WIDTH +: DATA_WIDTH] <= transposed_image_reg[(OUT_ROW-1-rot_row) * OUT_COL + rot_col] * DATA_WIDTH;

            // No Rotation (Pass-through)
            2'b11: rotated_image[(rot_row * OUT_COL + rot_col) * DATA_WIDTH +: DATA_WIDTH] <= transposed_image_reg[(rot_row * OUT_COL + rot_col) * DATA_WIDTH];
          endcase
        end
      end
    end
  end

  always_ff @(posedge clk) begin
    rotated_image_reg <= rotated_image;
  end

  // Step 4: Output Register for Added Latency
  always_ff @(posedge clk) begin
    if (srst) begin
      image_out <= '0;
    } else begin
      image_out <= rotated_image_reg;
    end
  end

endmodule

