always_ff @(posedge clk_in or posedge reset_in) begin
    if (reset_in)
        present_state <= idle;
    else
        present_state <= next_state;
end

always_comb begin
    case (present_state)
        idle: begin
            if (!started) begin
                if (ir_signal_in && !decoded) begin
                    started <= 1;
                    cycle_counter <= 0;
                    bit_counter <= 0;
                    ir_frame_reg <= 12'h0000;
                    decoded <= 0;
                    stored <= 0;
                    failed <= 0;
                    success <= 0;
                end else
                    failed <= 1;
            end else begin
                failed <= 0;
            end
        end

        start: begin
            if (started && ir_signal_in && (cycle_counter == 2400)) begin
                decoded <= 1;
                next_state <= decoding;
            end else
                failed <= 1;
        end

        decoding: begin
            if (ir_signal_in && (cycle_counter == 600 || cycle_counter == 1200 || cycle_counter == 1800 ||
                                 cycle_counter == 2400 || cycle_counter == 3000 || cycle_counter == 3600 ||
                                 cycle_counter == 4200 || cycle_counter == 4800 || cycle_counter == 5400 ||
                                 cycle_counter == 6000)) begin
                ir_frame_reg[bit_counter] <= ir_signal_in ? 12'h0001 : 12'h0000;
                bit_counter <= bit_counter + 1;
                if (bit_counter == 12) begin
                    next_state <= finish;
                end
            end else
                failed <= 1;
        end

        finish: begin
            if (bit_counter == 12) begin
                ir_frame_out <= ir_frame_reg;
                ir_frame_valid <= 1;
                next_state <= idle;
            end
        end
    endcase
end

module ir_receiver (
    input  logic        reset_in,               // Active HIGH reset
    input  logic        clk_in,                 // System clock (10 KHz, 100us)
    input  logic        ir_signal_in,           // Input signal (IR)
    output logic [6:0]  ir_function_code_out,   // Decoded output for different functions
    output logic [4:0]  ir_device_address_out,  // "00001": TV, "00010":HDMI1, "00100":USB, "01000":HDMI2, "10000": VCR
    output logic        ir_output_valid         // Indicates validity of the decoded frame
);

    typedef enum logic [2:0] {idle, start, decoding, finish, frame_space} ir_state;
    ir_state present_state, next_state;

    logic started;
    logic decoded;
    logic failed;
    logic success;
    logic frame_full;
    logic ir_frame_valid;

    int cycle_counter;
    int frame_space_counter;
    int bit_counter;

    logic [11:0] ir_frame_reg;
    logic [11:0] ir_frame_out;
    logic stored;

    always_ff @(posedge clk_in or posedge reset_in) begin
        if (reset_in)
            present_state <= idle;
        else
            present_state <= next_state;
    end

    always_comb begin
        case (present_state)
            idle: begin
                if (ir_signal_in == 1 && started == 0) begin
                    started <= 1;
                    next_state = start;
                end else
                    next_state = idle;
            end
            start: begin
                if (ir_signal_in == 0 && started == 1) begin
                    started <= 0;
                    next_state = decoding;
                end else if (failed == 1)
                    next_state = idle;
                else
                    next_state = start;
            end
            decoding: begin
                if (bit_counter == 12) begin
                    bit_counter <= 0;
                    decoded <= 1;
                    success <= 1;
                    next_state = finish;
                end else begin
                    bit_counter <= bit_counter + 1;
                    next_state = decoding;
                end
            end
            finish: begin
                if (success == 1) begin
                    frame_full <= 1;
                    next_state = frame_space;
                end else begin
                    next_state = finish;
                end
            end
            frame_space: begin
                if (frame_space_counter == 45) begin
                    frame_space_counter <= 0;
                    ir_frame_valid <= 1;
                    next_state = idle;
                end else begin
                    frame_space_counter <= frame_space_counter + 1;
                    next_state = frame_space;
                end
            end
        end
    end

    always_comb begin
        case (present_state)
            idle: begin
                ir_frame_reg <= 'b0;
            end
            start: begin
                ir_frame_reg <= ir_signal_in;
            end
            decoding: begin
                ir_frame_out <= ir_frame_reg;
            end
            finish: begin
                ir_function_code_out <= ir_frame_out[6:0];
                ir_device_address_out <= ir_frame_out[4:0];
                ir_output_valid <= 1;
            end
            frame_space: begin
                ir_output_valid <= 1;
            end
        end
    end

endmodule

