    end

    always_comb begin
        G1 = 0; G2 = 0; G3 = 0;
        P1 = 0; P2 = 0; P3 = 0;
        carry = 0;
        sum_comb = 0;

        for (int i = 0; i < 16; i++) begin
            G0[i] = A[i] & B[i];
            P0[i] = A[i] ^ B[i];
        end

        if (stage >= 0) begin
            for (int i = 0; i < 16; i++) begin
                if (i >= 1 && i != 3 && i != 7) begin  
                    G1[i] = G0[i] | (P0[i] & G0[i - 1]);
                    P1[i] = P0[i] & P0[i - 1];
                end else begin
                    G1[i] = G0[i];  
                    P1[i] = P0[i];
                end
            end
        end


        if (stage >= 1) begin
            for (int i = 0; i < 16; i++) begin
                if (i == 10) begin  
                    G2[i] = 1'b0;
                    P2[i] = 1'b1;
                end else if (i >= 2) begin
                    G2[i] = G1[i] | (P1[i] & G1[i - 2]);
                    P2[i] = P1[i] & P1[i - 2];
                end else begin
                    G2[i] = G1[i];
                    P2[i] = P1[i];
                end
            end
        end

        if (stage >= 2) begin
            for (int i = 0; i < 16; i++) begin
                if (i == 5) begin  
                    G3[i] = P2[i];
                    P3[i] = G2[i];
                end else if (i >= 4) begin
                    G3[i] = G2[i] | (P2[i] & G2[i - 4]);
                    P3[i] = P2[i] & P2[i - 4];
                end else begin
                    G3[i] = G2[i];
                    P3[i] = P2[i];
                end
            end
        end

        if (stage >= 3) begin
            carry[0] = 0;
            for (int i = 1; i <= 16; i++) begin
                carry[i] = G3[i - 1] | (P3[i - 1] & carry[i - 1]);
            end

            for (int i = 0; i < 16; i++) begin
                sum_comb[i] = P0[i] ^ carry[i];
            end
            sum_comb[16] = carry[16] ^ carry[5];  
        end
    end
endmodule

