module moving_average(
    input wire clk,
    input wire reset,
    input wire enable,
    input wire [11 : 0] data_in,
    output reg [11 : 0] data_out
);

reg [11 : 0] memory [7 : 0];
reg [14 : 0] sum;
reg [2 : 0] write_address;
wire [2 : 0] next_address;
reg [11 : 0] read_data;

assign next_address=write_address + 1'b1;
assign data_out=sum[14 : 3];

    // write current input to memory only when enable is high
    integer i;
    always @(posedge clk ) begin
        if (reset == 1'b1) begin
            for (i = 0 ;i < 8 ; i = i + 1 ) begin
                memory[i]<='h0;
            end
        end else if (enable == 1'b1) begin
            memory[write_address]<=data_in;
        end
    end

    // read the oldest element written to memory only when enable is high
    always @(posedge clk ) begin
        if(reset == 1'b1)begin
            read_data<='h0;
        end else if (enable == 1'b1) begin
            read_data<=memory[next_address];
        end
    end

    // increase the write address to move onto the next data only when enable is high
    always @(posedge clk ) begin
        if(reset == 1'b1)begin
            write_address<='h0;
        end else if (enable == 1'b1) begin
            write_address<=write_address + 1'b1;
        end
    end

    // calculate sum by adding the latest data to the sum and subtracting the oldest data only when enable is high
    always @(posedge clk ) begin
        if(reset == 1'b1)begin
            sum<='h0;
        end else if (enable == 1'b1) begin
            sum<=sum+data_in-read_data;
        end
    end

endmodule

output.rtl/mux_synch.sv:
module mux_synch (

	input [7:0] data_in,   				//asynchronous data input
	input req,                  		//indicating that data is available at the data_in input
	input dst_clk,                 		//destination clock
	input src_clk,                 		//source clock
	input nrst,                    		//asynchronous reset 
	output reg [7:0] data_out ); 		//synchronized version of data_in to the destination clock domain

    reg [1:0] sync_state;
    reg [7:0] sync_data;

    // Two flip-flops for synchronization
    always @(posedge dst_clk) begin
        if (nrst) begin
            sync_state <= 2'b00;
            sync_data <= 8'b0000_0000;
        end else if (sync_state == 2'b01) begin
            sync_data <= data_out;
            sync_state <= 2'b00;
        end else begin
            sync_data <= data_out;
            sync_state <= sync_state + 1;
        end
    end

    // Select data based on req and synchronize it
    always @(posedge src_clk) begin
        if (req) begin
            if (sync_state == 2'b00) begin
                data_out <= data_in;
                sync_state <= 2'b01;
            end
        end
    end

endmodule

module nff (

	input d_in,   									//input data that needs to be synchronized to the dst_clk domain.
	input dst_clk,     								//destination domain clock.
	input rst,         								//asynchronous active-low reset
	output reg  syncd 								//synced output, which is a 2-clock-cycle delayed version of d_in.
	                   );

    reg [1:0] sync_state;
    reg syncd_reg;

    // Two flip-flops for synchronization
    always @(posedge dst_clk) begin
        if (rst) begin
            syncd_reg <= 8'b0000_0000;
            sync_state <= 2'b00;
        end else if (sync_state == 2'b01) begin
            syncd_reg <= d_in;
            sync_state <= 2'b00;
        end else begin
            syncd_reg <= d_in;
            sync_state <= sync_state + 1;
        end
    end

    assign syncd = syncd_reg;

endmodule

