output.rtl/neuromorphic_array.sv:
module single_neuron_dut (
    input logic clk,
    input logic rst_n,
    input logic control,        // Control signal
    input logic [7:0] seq_in,   // Input sequence
    output logic [7:0] seq_out   // Output sequence
);
    logic [7:0] state;
    logic last_update;

    // Reset logic
    always @(posedge clk or posedge rst_n) begin
        if (rst_n) begin
            state <= 8'd0;
            last_update <= 1'b0;
        end else if (control) begin
            state <= seq_in;
            last_update <= 1'b1;
        end
    end

    // Sequential logic
    always @(posedge clk) begin
        if (last_update) begin
            seq_out <= state;
            last_update <= 1'b0;
        end
    end

endmodule

module neuromorphic_array #(
    parameter NEURONS = 8,       // Number of neurons
    parameter INPUTS = 8,        // Number of inputs
    parameter OUTPUTS = 8         // Number of outputs
) (
    input  logic [7:0] ui_in,       // Control input
    input logic [7:0] uio_in,      // Input data
    output logic [7:0] uo_out,     // Output data
    input logic clk,                // Clock
    input logic rst_n               // Reset
);
    // Internal wires for neuron outputs
    logic [7:0] neuron_outputs [0:NEURONS-1];

    // Instantiate the neurons
    genvar i;
    generate
        for (i = 0; i < NEURONS; i = i + 1) begin
            single_neuron_dut u_neuron_dut_inst(
                .clk(clk),
                .rst_n(rst_n),
                .control(ui_in[0]),
                .seq_in(uio_in),
                .seq_out(neuron_outputs[i])
            );
        end
    endgenerate

    // Combine outputs from the last neuron
    assign uo_out = neuron_outputs[NEURONS-1]; // Output from the last neuron

endmodule

input.rtl/one_hot_gen.sv:
module one_hot_gen #(
    parameter NS_A = 'd8,
    parameter NS_B = 'd4
) (
    input  logic                 clk,
    input  logic                 rst_async_n,
    input  logic [1:0]           i_config,
    input  logic                 i_start,
    input  logic                 o_ready,
    output logic [NS_A+NS_B-1:0] o_address_one_hot
);

typedef enum logic [2:0] {IDLE = 2'b00, REGION_A = 2'b01, REGION_B = 2'b10} state_t;

// ----------------------------------------
// - Wires/Registers creation
// ----------------------------------------
state_t state_ff, state_nx;
logic [NS_A-1:0] region_A_ff, region_A_nx;
logic [NS_B-1:0] region_B_ff, region_B_nx;
logic A_to_B, B_to_A, only_A, only_B;

// Input register
logic [2:0] config_ff;

// ----------------------------------------
// - Wire connections
// ----------------------------------------

// Region change flags
assign A_to_B = ( config_ff[1] & ~config_ff[0]);
assign B_to_A = ( config_ff[1] &  config_ff[0]);
assign only_A = (~config_ff[0] & ~config_ff[0]);
assign only_B = (~config_ff[0] &  config_ff[0]);

// Output assignment (Region A concatenated with Region B)
assign o_address_one_hot = {region_A_ff, region_B_ff};

// ----------------------------------------
// - Registers
// ----------------------------------------

always_ff @(posedge clk or negedge rst_async_n) begin : input_register
    if(~rst_async_n) begin
        config_ff <= 0;
    end else begin
        if(i_start && state_ff == IDLE) begin
            config_ff <= i_config;
        end
    end
end

always_ff @(posedge clk or negedge rst_async_n) begin : reset_regs
    if(~rst_async_n) begin
        o_ready <= 1;
        state_ff <= IDLE;
        region_A_ff <= {NS_A{1'b0}};
        region_B_ff <= {NS_B{1'b0}};
    end else begin
        o_ready <= (state_nx == IDLE);
        state_ff <= state_nx;
        region_A_ff <= region_A_nx;
        region_B_ff <= region_B_nx;
    end
end

// ----------------------------------------
// - One-hot address generation
// ----------------------------------------

always_comb begin : drive_regions
    case(state_ff)
        IDLE: begin
            if(i_start) begin
                region_A_nx[NS_A] = (~i_config[0]);
                region_B_nx[NS_B] = (i_config[0]);
            end else begin
                region_A_nx[NS_A] = 1'b0;
                region_B_nx[NS_B] = 1'b0;
            end

            region_A_nx[NS_A-2:0] = {(NS_A-1){1'b0}};
            region_B_nx[NS_B-2:0] = {(NS_B-1){1'b0}};
        end
        REGION_A: begin
            region_A_nx = region_A_ff >> 1;

            if(region_A_ff[0]) begin
                region_B_nx[NS_B] = A_to_B;
            end else begin
                region_B_nx[NS_B] = 1'b0;
            end
            region_B_nx[NS_B-2:0] = {(NS_B-1){1'b0}};
        end
        REGION_B: begin
            if(region_B_ff[0]) begin
                region_A_nx[NS_A] = B_to_A;
            end else begin
                region_A_nx[NS_A] = 1'b0;
            end
            region_A_nx[NS_A-2:0] = {(NS_A-1){1'b0}};

            region_B_nx = region_B_ff >> 1;
        end
        default: begin
            region_A_nx = {NS_A{1'b0}};
            region_B_nx = {NS_B{1'b0}};
        end
    endcase
end

// ----------------------------------------
// - FSM update
// ----------------------------------------

always_comb begin : update_state
    case(state_ff)
        IDLE: begin
            if(i_start) begin
                if(i_config[0]) begin
                    state_nx = REGION_B;
                end else begin
                    state_nx = REGION_A;
                end
            end else begin
                state_nx = IDLE;
            end
        end
        REGION_A: begin
            if(region_A_ff[0]) begin
                if(A_to_B) begin
                    state_nx = REGION_B;
                end else begin
                    state_nx = IDLE;
                end
            end else begin
                state_nx = REGION_A;
            end
        end
        REGION_B: begin
            if(region_B_ff[0]) begin
                if(B_to_A) begin
                    state_nx = REGION_A;
                end else begin
                    state_nx = IDLE;
                end
            end else begin
                state_nx = REGION_B;
            end
        end
        default: begin
            state_nx = IDLE;
        end
    endcase
end

endmodule : one_hot_gen

output.rtl/one_hot_gen.sv:
module one_hot_gen #(
    parameter NS_A = 'd8,
    parameter NS_B = 'd4
) (
    input  logic                 clk,
    input  logic                 rst_async_n,
    input  logic [1:0]           i_config,
    input  logic                 i_start,
    input  logic                 o_ready,
    output logic [NS_A+NS_B-1:0] o_address_one_hot
);

typedef enum logic [2:0] {IDLE = 2'b00, REGION_A = 2'b01, REGION_B = 2'b10} state_t;

// ----------------------------------------
// - Wires/Registers creation
// ----------------------------------------
state_t state_ff, state_nx;
logic [NS_A-1:0] region_A_ff, region_A_nx;
logic [NS_B-1:0] region_B_ff, region_B_nx;
logic A_to_B, B_to_A, only_A, only_B;

// Input register
logic [2:0] config_ff;

// ----------------------------------------
// - Wire connections
// ----------------------------------------

// Region change flags
assign A_to_B = ( config_ff[1] & ~config_ff[0]);
assign B_to_A = ( config_ff[1] &  config_ff[0]);
assign only_A = (~config_ff[0] & ~config_ff[0]);
assign only_B = (~config_ff[0] &  config_ff[0]);

// Output assignment (Region A concatenated with Region B)
assign o_address_one_hot = {region_A_ff, region_B_ff};

// ----------------------------------------
// - Registers
// ----------------------------------------

always_ff @(posedge clk or negedge rst_async_n) begin : input_register
    if(~rst_async_n) begin
        config_ff <= 0;
    end else begin
        if(i_start && state_ff == IDLE) begin
            config_ff <= i_config;
        end
    end
end

always_ff @(posedge clk or negedge rst_async_n) begin : reset_regs
    if(~rst_async_n) begin
        o_ready <= 1;
        state_ff <= IDLE;
        region_A_ff <= {NS_A{1'b0}};
        region_B_ff <= {NS_B{1'b0}};
    end else begin
        o_ready <= (state_nx == IDLE);
        state_ff <= state_nx;
        region_A_ff <= region_A_nx;
        region_B_ff <= region_B_nx;
    end
end

// ----------------------------------------
// - One-hot address generation
// ----------------------------------------

always_comb begin : drive_regions
    case(state_ff)
        IDLE: begin
            if(i_start) begin
                region_A_nx[NS_A] = (~i_config[0]);
                region_B_nx[NS_B] = (i_config[0]);
            end else begin
                region_A_nx[NS_A] = 1'b0;
                region_B_nx[NS_B] = 1'b0;
            end

            region_A_nx[NS_A-2:0] = {(NS_A-1){1'b0}};
            region_B_nx[NS_B-2:0] = {(NS_B-1){1'b0}};
        end
        REGION_A: begin
            region_A_nx = region_A_ff >> 1;

            if(region_A_ff[0]) begin
                region_B_nx[NS_B] = A_to_B;
            end else begin
                region_B_nx[NS_B] = 1'b0;
            end
            region_B_nx[NS_B-2:0] = {(NS_B-1){1'b0}};
        end
        REGION_B: begin
            if(region_B_ff[0]) begin
                region_A_nx[NS_A] = B_to_A;
            end else begin
                region_A_nx[NS_A] = 1'b0;
            end
            region_A_nx[NS_A-2:0] = {(NS_A-1){1'b0}};

            region_B_nx = region_B_ff >> 1;
        end
        default: begin
            region_A_nx = {NS_A{1'b0}};
            region_B_nx = {NS_B{1'b0}};
        end
    endcase
end

// ----------------------------------------
// - FSM update
// ----------------------------------------

always_comb begin : update_state
    case(state_ff)
        IDLE: begin
            if(i_start) begin
                if(i_config[0]) begin
                    state_nx = REGION_B;
                end else begin
                    state_nx = REGION_A;
                end
            end else begin
                state_nx = IDLE;
            end
        end
        REGION_A: begin
            if(region_A_ff[0]) begin
                if(A_to_B) begin
                    state_nx = REGION_B;
                end else begin
                    state_nx = IDLE;
                end
            end else begin
                state_nx = REGION_A;
            end
        end
        REGION_B: begin
            if(region_B_ff[0]) begin
                if(B_to_A) begin
                    state_nx = REGION_A;
                end else begin
                    state_nx = IDLE;
                end
            end else begin
                state_nx = REGION_B;
            end
        end
        default: begin
            state_nx = IDLE;
        end
    endcase
end

endmodule : one_hot_gen

output.rtl/packet_controller.sv:
module packet_controller(
    input clk,
    input rst,
    input rx_valid_i,
    input [7:0] rx_data_8_i,
    input tx_done_tick_i,
    output reg tx_start_o,
    output reg [7:0] tx_data_8_o
);

    // State declaration
    typedef enum {S_IDLE, S_GOT_8_BYTES, S_RECV_CHECKSUM, S_BUILD_RESPONSE, S_SEND_FIRST_BYTE, S_RESPONSE_READY} state_t;
    state_t state, next_state;

    // Registers for storing packet data
    reg [15:0] packet_data_acc;
    reg [7:0] packet_checksum;

    // Constants for packet format
    reg [15:0] valid_header = 31'b110010101100;
    reg [15:0] response_header = 31'b101010101100;

    // FSM state logic
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= S_IDLE;
            tx_start_o <= 1'b0;
            packet_data_acc <= 0;
            packet_checksum <= 0;
        end else begin
            state <= next_state;
        end
    end

    // State transition logic
    always @(*) begin
        case (state)
            S_IDLE: begin
                if (rx_valid_i) begin
                    packet_data_acc <= packet_data_acc + rx_data_8_i;
                    if (packet_data_acc == 8'hBACD) begin
                        next_state = S_GOT_8_BYTES;
                    end else next_state = S_IDLE;
                end
            end
            S_GOT_8_BYTES: begin
                packet_checksum = packet_data_acc + rx_data_8_i + rx_data_8_i + rx_data_8_i + rx_data_8_i + rx_data_8_i + rx_data_8_i + rx_data_8_i; // Calculate checksum
                if (packet_checksum == 8'h00000000) begin
                    next_state = S_RECV_CHECKSUM;
                end else next_state = S_IDLE;
            end
            S_RECV_CHECKSUM: begin
                if (packet_checksum == 8'h00000000) begin
                    // Valid header, compute response
                    // Assuming opcode 8'h00 for addition
                    tx_data_8_o = response_header + (rx_data_8_i + rx_data_8_i) + rx_data_8_i; // Simplified response logic
                    next_state = S_SEND_FIRST_BYTE;
                end else next_state = S_IDLE;
            end
            S_SEND_FIRST_BYTE: begin
                tx_start_o <= 1'b1;
                next_state = S_RESPONSE_READY;
            end
            S_RESPONSE_READY: begin
                // Transmit remaining bytes of response
                // Assuming opcode 8'h00 for addition
                // This should be repeated for each byte in the response
                // For simplicity, we're only transmitting one byte here
                tx_data_8_o = response_header + (rx_data_8_i + rx_data_8_i) + rx_data_8_i;
                next_state = S_SEND_FIRST_BYTE;
            end
            default: next_state = S_IDLE;
        end
    end

    // Transmission logic
    always @(posedge tx_done_tick_i) begin
        if (tx_start_o) begin
            // Transmit tx_data_8_o
            // This is a placeholder for the actual transmission logic
        end
    end

endmodule

