module palindrome_detect #(
parameter N=3
) (
input clk,
input reset,
input [N-1:0] bit_stream,
output reg palindrome_detected
);

reg [N-1:0] buffer[0:N-1];
reg [N-1:0] palindrome;

always @(posedge clk or posedge reset) begin
    if (reset) begin
        buffer <= {N{1'b0}};
        palindrome <= 0;
        palindrome_detected <= 0;
    end else begin
        buffer <= {buffer[N-2:0], bit_stream};
        palindrome <= buffer[N-1:0];
        if (buffer[0] == palindrome) begin
            palindrome_detected <= 1;
        end else begin
            palindrome_detected <= 0;
        end
    end
end

endmodule

output.rtl/password_generator.sv:
module password_generator #(
    parameter WIDTH = 4  
) (
    input logic clk,
    input logic reset,
    output logic [(WIDTH*8)-1:0] password 
);

  logic [7:0] char_array[WIDTH-1:0];  
  logic [7:0] counter;  
  logic [1:0] char_type; 

  int i;

  // Counter Logic for pseudo-random generation
  always_ff @(posedge clk) begin
    if (reset) begin
      counter <= 8'd0;
      char_array <= {8'h0, 8'h0, 8'h0, 8'h0};
    end else begin
      counter <= counter + 1;
    end
  end

  // Generate password characters
  always_comb begin
    for (i = 0; i < WIDTH; i = i + 1) begin
      case (char_type)
        2'b00: char_array[i] = (counter + char_array[(i+1)%WIDTH]) % 26 + 8'd97; // Lowercase
        2'b01: char_array[i] = (counter + i) % 26 + 8'd65; // Uppercase
        2'b10: char_array[i] = (counter + char_array[(i+WIDTH-1)%WIDTH]) % 14 + 8'd33; // Special
        2'b11: char_array[i] = (counter + i) % 10 + 8'd48; // Numeric
      endcase
    end
  end

  // Pack the char_array into the password signal
  assign password = {char_array[WIDTH-1], char_array[WIDTH-2], char_array[WIDTH-3], char_array[WIDTH-4]};

endmodule

output.rtl/perceptron_gates.sv:
module perceptron_gates #(
    parameter BITWIDTH_INPUT = 4,
    parameter BITWIDTH_WEIGHT = 4,
    parameter BITWIDTH_BIAS = 4,
    parameter BITWIDTH_TARGET = 3,
    parameter BITWIDTH_PREV_WEIGHT = 4,
    parameter BITWIDTH_PREV_BIAS = 4,
    parameter BITWIDTH_STOP = 1
) (
    input clk,
    input rst_n,
    input [BITWIDTH_INPUT-1:0] x1,
    input [BITWIDTH_INPUT-1:0] x2,
    input [BITWIDTH_TARGET-1:0] threshold,
    input [1:0] gate_select,
    input [BITWIDTH_TARGET-1:0] input_index,
    output [BITWIDTH_WEIGHT-1:0] percep_w1,
    output [BITWIDTH_WEIGHT-1:0] percep_w2,
    output [BITWIDTH_BIAS-1:0] percep_bias,
    output present_addr,
    output stop,
    output [BITWIDTH_TARGET-1:0] y_in,
    output [BITWIDTH_TARGET-1:0] y,
    output [BITWIDTH_PREV_WEIGHT-1:0] prev_percep_wt_1,
    output [BITWIDTH_PREV_WEIGHT-1:0] prev_percep_wt_2,
    output [BITWIDTH_PREV_BIAS-1:0] prev_percep_bias
);

    // Define submodules
    gate_target u_gate_target (
        .gate_select(gate_select),
        .o_1(), .o_2(), .o_3(), .o_4()
    );
    microcode_rom u_microcode_rom (
        .clk, .rst, .addr, .weights, .bias, .target, .input_index
    );

    // Define internal signals
    logic [BITWIDTH_WEIGHT-1:0] wt1_update, wt2_update, bias_update;
    logic [BITWIDTH_BIAS-1:0] prev_percep_wt_1, prev_percep_wt_2, prev_percep_bias;
    logic [BITWIDTH_TARGET-1:0] y_out, target;

    // Initialize weights and bias
    always_comb
    begin
        if (!rst_n)
            percep_w1 = 4'd0;
        percep_w2 = 4'd0;
        percep_bias = 4'd0;
        prev_percep_wt_1 = 4'd0;
        prev_percep_wt_2 = 4'd0;
        prev_percep_bias = 4'd0;
    end

    // Compute output
    always_ff @(posedge clk) begin
        if (!rst_n) begin
            y_in = percep_bias + (x1 * percep_w1) + (x2 * percep_w2);
            y = (y_in > threshold) ? 4'd1 : (y_in < -threshold) ? 4'd0 : -4'd1;
        end
    end

    // Select target value
    always_comb
    begin
        target = u_gate_target.o_1();
        case (gate_select)
            2'b00: target = 4'd1;
            2'b01: target = 4'd1;
            2'b10: target = 4'd1;
            2'b11: target = 4'd1;
        endcase
    end

    // Update weights and bias
    always_ff @(posedge clk) begin
        if (!rst_n) begin
            if (target != y) begin
                wt1_update = learning_rate * x1 * target;
                wt2_update = learning_rate * x2 * target;
                bias_update = learning_rate * target;
            end else begin
                wt1_update = 4'd0;
                wt2_update = 4'd0;
                bias_update = 4'd0;
            end
        end
    end

    // Compare weights and bias to check for convergence
    always_ff @(posedge clk) begin
        if (!rst_n) begin
            if (wt1_update == prev_percep_wt_1 && wt2_update == prev_percep_wt_2 && bias_update == prev_percep_bias)
                stop = 1'b1;
            else
                prev_percep_wt_1 = wt1_update;
            prev_percep_wt_2 = wt2_update;
            prev_percep_bias = bias_update;
        end
    end

    // Update weights and bias signals
    assign percep_w1 = percep_w1 + wt1_update;
    assign percep_w2 = percep_w2 + wt2_update;
    assign percep_bias = percep_bias + bias_update;

    // Output the current address for the microcode ROM
    assign present_addr = u_microcode_rom.addr;

endmodule

input.rtl/perceptron_gates.sv:
module perceptron_gates (
   input  logic clk,// Posedge clock
   input  logic rst_n,// Negedge reset
   input  logic signed [3:0] x1, // First Input of the Perceptron
   input  logic signed [3:0] x2, // Second Input of the Perceptron
   input  logic learning_rate, // Learning rate (alpha)
   input  logic signed [3:0] threshold, // Threshold value
   input  logic [1:0] gate_select, // Gate selection for target values
   output logic signed [3:0] percep_w1, // Trained Weight 1 
   output logic signed [3:0] percep_w2, // Trained Weight 2
   output logic signed [3:0] percep_bias, // Trained Bias
   output logic [3:0] present_addr, // Current address in microcode ROM
   output logic stop, // Condition to indicate no learning has occurred(i.e. no weight change between iterations)
   output logic [2:0] input_index,// Vector to track the selection of target for a given input combination for a gate
   output logic signed [3:0] y_in, // Calculated Response
   output logic signed [3:0] y, // Calculated Response obtained by comparing y_in against a threshold value
   output logic signed [3:0] prev_percep_wt_1,//Value of Weight 1 during a previous iteration
   output logic signed [3:0] prev_percep_wt_2,//Value of Weight 2 during a previous iteration
   output logic signed [3:0] prev_percep_bias // Value of Bias during a previous iteration
);

   logic [15:0] microcode_rom [0:5];
   logic [3:0]  next_addr;
   logic [3:0]  train_action;
   logic [3:0]  microcode_addr;
   logic [15:0] microinstruction;
   logic signed [3:0] t1, t2, t3, t4;

   gate_target dut (
       .gate_select(gate_select),
       .o_1(t1),
       .o_2(t2),
       .o_3(t3),
       .o_4(t4)
   );

   logic signed [3:0] percep_wt_1_reg;
   logic signed [3:0] percep_wt_2_reg;
   logic signed [3:0] percep_bias_reg;


   logic signed [3:0] target;
   logic signed [3:0] prev_wt1_update;
   logic signed [3:0] prev_wt2_update;
   logic signed [3:0] prev_bias_update;

   logic signed [3:0] wt1_update;
   logic signed [3:0] wt2_update;
   logic signed [3:0] bias_update;
   logic [7:0] epoch_counter;

   assign  prev_percep_wt_1 = prev_wt1_update;
   assign  prev_percep_wt_2 = prev_wt2_update;
   assign  prev_percep_bias = prev_bias_update;

   initial begin 
      microcode_rom[0] = 16'b0001_0000_0000_0000; 
      microcode_rom[1] = 16'b0010_0001_0000_0000; 
      microcode_rom[2] = 16'b0011_0010_0000_0000; 
      microcode_rom[3] = 16'b0100_0011_0000_0000; 
      microcode_rom[4] = 16'b0101_0100_0000_0000; 
      microcode_rom[5] = 16'b0000_0101_0000_0000; 
   end  

   always@(*) begin
      microinstruction = microcode_rom[microcode_addr];
      next_addr        = microinstruction[15:12];
      train_action     = microinstruction[11:8];
   end

   always_ff @(posedge clk or negedge rst_n) begin
      if (!rst_n) begin
         present_addr    <= 4'd0;
         microcode_addr  <= 4'd0;
         percep_wt_1_reg <= 4'd0;
         percep_wt_2_reg <= 4'd0;
         percep_bias_reg <= 4'd0;
         input_index     <= 2'd0;
         stop            <= 1'b0;
      end else begin
         present_addr    <= next_addr;
         microcode_addr  <= present_addr;
      end
   end

   always_comb begin
      case (train_action)
         4'd0:  begin 
                   percep_wt_1_reg = 4'd0;
                   percep_wt_2_reg = 4'd0;
                   percep_bias_reg = 4'd0;
                   stop = 1'b0;
                   next_addr = next_addr + 4'd0;
                   y_in = 4'd0;
                   y    = 4'd0;
                   prev_wt1_update = 4'd0;
                   prev_wt2_update = 4'd0;
                   prev_bias_update = 4'd0;
                   input_index = 0;
                   target = 0;
                   wt1_update = 0;
                   wt2_update = 0;
                   bias_update = 0;
                   epoch_counter = 0;
                end
         4'd1 : begin 
                   y_in = percep_bias_reg + (x1 * percep_wt_1_reg) + (x2 * percep_wt_2_reg); 
                   if (y_in > threshold)
                      y = 4'd1;
                   else if (y_in >= -threshold && y_in <= threshold)
                      y = 4'd0;
                   else
                      y = -4'd1;

                   percep_wt_1_reg  = percep_wt_1_reg  + 4'd0;
                   percep_wt_2_reg  = percep_wt_2_reg  + 4'd0;
                   percep_bias_reg  = percep_bias_reg  + 4'd0;
                   prev_wt1_update  = prev_wt1_update  + 4'd0;
                   prev_wt2_update  = prev_wt2_update  + 4'd0;
                   prev_bias_update = prev_bias_update + 4'd0;
                   input_index = input_index + 0;
                   next_addr = next_addr + 4'd0;
                   stop = stop + 1'b0;
                   target = target + 4'd0;
                   wt1_update = wt1_update + 4'd0 ;
                   wt2_update = wt2_update + 4'd0 ;
                   bias_update = bias_update + 4'd0 ;
                   epoch_counter = epoch_counter + 0;
                end
         4'd2 : begin
                   if(input_index == 0)
                        target = t1;
                   else if(input_index == 1)
                        target = t2;
                   else if(input_index == 2)
                        target = t3;
                   else if(input_index == 3)
                        target = t4;
                   else begin
                        input_index = 0;
                        target = 0;
                   end
                   stop = stop + 1'b0;
                   input_index = input_index + 0;
                   next_addr = next_addr + 4'd0;
                   target = target + 4'd0;
                   prev_wt1_update  = prev_wt1_update  + 4'd0;
                   prev_wt2_update  = prev_wt2_update  + 4'd0;
                   prev_bias_update = prev_bias_update + 4'd0;

                   percep_wt_1_reg = percep_wt_1_reg + 4'd0;
                   percep_wt_2_reg = percep_wt_2_reg + 4'd0;
                   percep_bias_reg = percep_bias_reg + 4'd0;
                   y_in = y_in + 4'd0;
                   y = y + 4'd0;
                   wt1_update = wt1_update + 4'd0 ;
                   wt2_update = wt2_update + 4'd0 ;
                   bias_update = bias_update + 4'd0 ;
                   epoch_counter = epoch_counter + 0;
                end
         4'd3 : begin
                   if (y != target) begin
                        wt1_update = learning_rate * x1 * target ;
                        wt2_update = learning_rate * x2 * target ;
                        bias_update = learning_rate * target ; 
                    end else begin
                        wt1_update = 0 ;
                        wt2_update = 0 ;
                        bias_update = 0 ;     
                    end    
                    percep_wt_1_reg = percep_wt_1_reg + wt1_update;
                    percep_wt_2_reg = percep_wt_2_reg + wt2_update;
                    percep_bias_reg = percep_bias_reg + bias_update;
                    prev_wt1_update  = prev_wt1_update  + 4'd0;
                    prev_wt2_update  = prev_wt2_update  + 4'd0;
                    prev_bias_update = prev_bias_update + 4'd0;
                    y_in = y_in + 4'd0;
                    y = y + 4'd0;
                    stop = stop + 1'b0;
                    input_index = input_index + 0;
                    next_addr = next_addr + 4'd0;
                    target = target + 4'd0;
                    epoch_counter = epoch_counter + 0;
                end
         4'd4 : begin
                  if ((prev_wt1_update == wt1_update) & (prev_wt2_update == wt2_update) & (input_index == 4'd3)) begin 
                          epoch_counter = 0;
                          stop = 1'b1; 
                          input_index = 0;
                          next_addr = 4'd0;
                          percep_wt_1_reg = 0;
                          percep_wt_2_reg = 0;
                          percep_bias_reg = 0;
                          prev_wt1_update =  0;
                          prev_wt2_update =  0;
                          prev_bias_update = 0;
                          y_in = 0;
                          y = 0;
                          target = 0;
                          wt1_update = 0 ;
                          wt2_update = 0 ;
                          bias_update = 0 ;
                  end else begin
                          stop = 1'b0; 
                          input_index = input_index + 0;
                          epoch_counter = epoch_counter + 1;    
                          next_addr = 4'd5;    
                          percep_wt_1_reg = percep_wt_1_reg + 4'd0;
                          percep_wt_2_reg = percep_wt_2_reg + 4'd0;
                          percep_bias_reg = percep_bias_reg + 4'd0;
                          prev_wt1_update = prev_wt1_update + 4'd0;
                          prev_wt2_update = prev_wt2_update + 4'd0;
                          prev_bias_update = prev_bias_update + 4'd0;
                          y_in = y_in + 4'd0;
                          y = y + 4'd0;
                          target = target + 4'd0;
                          wt1_update = wt1_update + 4'd0 ;
                          wt2_update = wt2_update + 4'd0 ;
                          bias_update = bias_update + 4'd0 ;
                  end
                end
         4'd5 : begin
                          percep_wt_1_reg = percep_wt_1_reg + 4'd0;
                          percep_wt_2_reg = percep_wt_2_reg + 4'd0;
                          percep_bias_reg = percep_bias_reg + 4'd0;
                          prev_wt1_update  = wt1_update;
                          prev_wt2_update  = wt2_update;
                          prev_bias_update = bias_update;
                          next_addr = 4'd1;
                          input_index = input_index + 1;
                          stop = stop + 1'b0;
                          epoch_counter = epoch_counter + 0;
                          y_in = y_in + 4'd0;
                          y = y + 4'd0;
                          target = target + 4'd0;
                          wt1_update = wt1_update + 4'd0;
                          wt2_update = wt2_update + 4'd0;
                          bias_update = bias_update + 4'd0;
                end   
      default : begin
                          next_addr = next_addr + 4'd0;
                          percep_wt_1_reg = percep_wt_1_reg + 4'd0;
                          percep_wt_2_reg = percep_wt_2_reg + 4'd0;
                          percep_bias_reg = percep_bias_reg + 4'd0;
                          prev_wt1_update = prev_wt1_update + 4'd0;
                          prev_wt2_update = prev_wt2_update + 4'd0;
                          prev_bias_update = prev_bias_update + 4'd0;
                          stop = stop + 1'b0;
                          y_in = y_in + 4'd0;
                          y = y + 4'd0;
                          input_index = input_index + 0;
                          target = target + 4'd0;
                          wt1_update = wt1_update + 4'd0 ;
                          wt2_update = wt2_update + 4'd0 ;
                          bias_update = bias_update + 4'd0 ;
                          epoch_counter = epoch_counter + 0;
                end
      endcase
   end
   assign percep_w1 = percep_wt_1_reg;
   assign percep_w2 = percep_wt_2_reg;
   assign percep_bias = percep_bias_reg;

endmodule

module gate_target(
   input  logic        [1:0] gate_select,
   output logic signed [3:0] o_1,
   output logic signed [3:0] o_2,
   output logic signed [3:0] o_3,
   output logic signed [3:0] o_4
);
   always_comb begin
     case(gate_select)
          2'b00 : begin 
                    o_1 =  1; 
                    o_2 = -1; 
                    o_3 = -1; 
                    o_4 = -1; 
                  end
          2'b01 : begin 
                    o_1 =  1; 
                    o_2 =  1; 
                    o_3 =  1; 
                    o_4 = -1; 
                  end
          2'b10 : begin 
                    o_1 =  1; 
                    o_2 =  1; 
                    o_3 =  1; 
                    o_4 = -1; 
                  end
          2'b11 : begin 
                    o_1 =  1; 
                    o_2 = -1; 
                    o_3 = -1; 
                    o_4 = -1; 
                  end
        default : begin
                    o_1 =  0; 
                    o_2 =  0; 
                    o_3 =  0; 
                    o_4 =  0; 
                  end
        endcase
   end
endmodule

output.rtl/perceptron_gates.sv:
module perceptron_gates (
   input  logic clk,// Posedge clock
   input  logic rst_n,// Negedge reset
   input  logic signed [3:0] x1, // First Input of the Perceptron
   input  logic signed [3:0] x2, // Second Input of the Perceptron
   input  logic signed [3:0] threshold, // Threshold value
   input  logic [1:0] gate_select, // Gate selection for target values
   input  logic signed [3:0] test_percep_x1, // Testing input 1
   input  logic signed [3:0] test_percep_x2, // Testing input 2
   input  logic signed [3:0] test_expected_output, // Expected output for testing
   input  logic [1:0] test_percep_present_state, // Present state of Testing microcode ROM
   input  logic [3:0] test_percep_output, // Output from Testing microcode ROM
   input  logic signed [3:0] test_percep_result, // Number of times expected_output matched with test_output
   input  logic signed [3:0] test_percep_done, // Completion of Testing operation
   output logic signed [3:0] percep_w1, // Trained Weight 1 
   output logic signed [3:0] percep_w2, // Trained Weight 2
   output logic signed [3:0] percep_bias, // Trained Bias
   output logic [3:0] present_addr, // Current address in microcode ROM
   output logic stop, // Condition to indicate no learning has occurred(i.e. no weight change between iterations)
   output logic [2:0] input_index,// Vector to track the selection of target for a given input combination for a gate
   output logic signed [3:0] y_in, // Calculated Response
   output logic signed [3:0] y, // Calculated Response obtained by comparing y_in against a threshold value
   output logic signed [3:0] prev_percep_wt_1,//Value of Weight 1 during a previous iteration
   output logic signed [3:0] prev_percep_wt_2,//Value of Weight 2 during a previous iteration
   output logic signed [3:0] prev_percep_bias // Value of Bias during a previous iteration
   // Testing inputs and expected outputs
   input  logic signed [3:0] test_percep_x1,
   input  logic signed [3:0] test_percep_x2,
   input  logic signed [3:0] test_expected_output
   // Testing control unit outputs
   output logic signed [3:0] test_percep_present_state,
   output logic signed [3:0] test_percep_output,
   output logic signed [3:0] test_percep_result,
   output logic signed [3:0] test_percep_done
);

   logic [15:0] microcode_rom [0:5];
   logic [15:0] test_microcode_rom [0:5];
   logic [3:0]  next_addr;
   logic [3:0]  train_action;
   logic [3:0]  microcode_addr;
   logic [15:0] microinstruction;
   logic signed [3:0] t1, t2, t3, t4;

   gate_target dut (
       .gate_select(gate_select),
       .o_1(t1),
       .o_2(t2),
       .o_3(t3),
       .o_4(t4)
   );

   logic signed [3:0] percep_wt_1_reg;
   logic signed [3:0] percep_wt_2_reg;
   logic signed [3:0] percep_bias_reg;


   logic signed [3:0] target;
   logic signed [3:0] prev_wt1_update;
   logic signed [3:0] prev_wt2_update;
   logic signed [3:0] prev_bias_update;

   logic signed [3:0] wt1_update;
   logic signed [3:0] wt2_update;
   logic signed [3:0] bias_update;
   logic [7:0] epoch_counter;

   assign  prev_percep_wt_1 = prev_wt1_update;
   assign  prev_percep_wt_2 = prev_wt2_update;
   assign  prev_percep_bias = prev_bias_update;

   // Training microcode ROM
   initial begin 
      microcode_rom[0] = 16'b0001_0000_0000_0000; 
      microcode_rom[1] = 16'b0010_0001_0000_0000; 
      microcode_rom[2] = 16'b0011_0010_0000_0000; 
      microcode_rom[3] = 16'b0100_0011_0000_0000; 
      microcode_rom[4] = 16'b0101_0100_0000_0000; 
      microcode_rom[5] = 16'b0000_0101_0000_0000; 
   end  

   // Testing microcode ROM
   initial begin
      test_microcode_rom[0] = 16'b0001_0000_0000_0000; 
      test_microcode_rom[1] = 16'b0010_0001_0000_0000; 
      test_microcode_rom[2] = 16'b0011_0010_0000_0000; 
      test_microcode_rom[3] = 16'b0100_0011_0000_0000; 
      test_microcode_rom[4] = 16'b0101_0100_0000_0000; 
      test_microcode_rom[5] = 16'b0000_0101_0000_0000; 
   end

   always@(*) begin
      microinstruction = microcode_rom[microcode_addr];
      test_microinstruction = test_microcode_rom[test_percep_present_state];
      next_addr        = microinstruction[15:12];
      train_action     = microinstruction[11:8];
   end

   always_ff @(posedge clk or negedge rst_n) begin
      if (!rst_n) begin
         present_addr    <= 4'd0;
         microcode_addr  <= 4'd0;
         percep_wt_1_reg <= 4'd0;
         percep_wt_2_reg <= 4'd0;
         percep_bias_reg <= 4'd0;
         input_index     <= 2'd0;
         stop            <= 1'b0;
         test_percep_present_state <= 4'd0;
         test_percep_output <= 4'd0;
         test_percep_result <= 4'd0;
         test_percep_done       <= 4'd0;
      end else begin
         present_addr    <= next_addr;
         microcode_addr  <= present_addr;
      end
   end

   always_comb begin
      case (train_action)
         4'd0:  begin 
                   percep_wt_1_reg = 4'd0;
                   percep_wt_2_reg = 4'd0;
                   percep_bias_reg = 4'd0;
                   stop = 1'b0;
                   next_addr = next_addr + 4'd0;
                   y_in = 4'd0;
                   y    = 4'd0;
                   prev_wt1_update = 4'd0;
                   prev_wt2_update = 4'd0;
                   prev_bias_update = 4'd0;
                   input_index = 0;
                   target = 0;
                   wt1_update = 0;
                   wt2_update = 0;
                   bias_update = 0;
                   epoch_counter = 0;
                end
         4'd1: begin 
                   y_in = percep_bias_reg + (x1 * percep_wt_1_reg) + (x2 * percep_wt_2_reg); 
                   if (y_in > threshold)
                      y = 4'd1;
                   else if (y_in >= -threshold && y_in <= threshold)
                      y = 4'd0;
                   else
                      y = -4'd1;

                   percep_wt_1_reg  = percep_wt_1_reg  + 4'd0;
                   percep_wt_2_reg  = percep_wt_2_reg  + 4'd0;
                   percep_bias_reg  = percep_bias_reg  + 4'd0;
                   prev_wt1_update  = prev_wt1_update  + 4'd0;
                   prev_wt2_update  = prev_wt2_update  + 4'd0;
                   prev_bias_update = prev_bias_update + 4'd0;
                   input_index = input_index + 0;
                   next_addr = next_addr + 4'd0;
                   stop = stop + 1'b0;
                   target = target + 4'd0;
                   wt1_update = wt1_update + 4'd0 ;
                   wt2_update = wt2_update + 4'd0 ;
                   bias_update = bias_update + 4'd0 ;
                   epoch_counter = epoch_counter + 0;
                end
         4'd2: begin
                   if(input_index == 0)
                        target = t1;
                   else if(input_index == 1)
                        target = t2;
                   else if(input_index == 2)
                        target = t3;
                   else if(input_index == 3)
                        target = t4;
                   else begin
                        input_index = 0;
                        target = 0;
                   end
                   stop = stop + 1'b0;
                   input_index = input_index + 0;
                   next_addr = next_addr + 4'd0;
                   target = target + 4'd0;
                   prev_wt1_update  = prev_wt1_update  + 4'd0;
                   prev_wt2_update  = prev_wt2_update  + 4'd0;
                   prev_bias_update = prev_bias_update + 4'd0;

                   percep_wt_1_reg = percep_wt_1_reg + 4'd0;
                   percep_wt_2_reg = percep_wt_2_reg + 4'd0;
                   percep_bias_reg = percep_bias_reg + 4'd0;
                   y_in = y_in + 4'd0;
                   y = y + 4'd0;
                   wt1_update = wt1_update + 4'd0 ;
                   wt2_update = wt2_update + 4'd0 ;
                   bias_update = bias_update + 4'd0 ;
                   epoch_counter = epoch_counter + 0;
                end
         4'd3: begin
                   if (y != target) begin
                        wt1_update = learning_rate * x1 * target ;
                        wt2_update = learning_rate * x2 * target ;
                        bias_update = learning_rate * target ; 
                    end else begin
                        wt1_update = 0 ;
                        wt2_update = 0 ;
                        bias_update = 0 ;     
                    end    
                    percep_wt_1_reg = percep_wt_1_reg + wt1_update;
                    percep_wt_2_reg = percep_wt_2_reg + wt2_update;
                    percep_bias_reg = percep_bias_reg + bias_update;
                    prev_wt1_update  = prev_wt1_update  + 4'd0;
                    prev_wt2_update  = prev_wt2_update  + 4'd0;
                    prev_bias_update = prev_bias_update + 4'd0;
                    y_in = y_in + 4'd0;
                    y = y + 4'd0;
                    stop = stop + 1'b0;
                    input_index = input_index + 0;
                    next_addr = next_addr + 4'd0;
                    target = target + 4'd0;
                    epoch_counter = epoch_counter + 0;
                end
         4'd4: begin
                  if ((prev_wt1_update == wt1_update) & (prev_wt2_update == wt2_update) & (input_index == 4'd3)) begin 
                          epoch_counter = 0;
                          stop = 1'b1; 
                          input_index = 0;
                          next_addr = 4'd0;
                          percep_wt_1_reg = 0;
                          percep_wt_2_reg = 0;
                          percep_bias_reg = 0;
                          prev_wt1_update =  0;
                          prev_wt2_update =  0;
                          prev_bias_update = 0;
                          y_in = 0;
                          y = 0;
                          target = 0;
                          test_percep_output <= 4'b0;
                          test_percep_result <= test_percep_result + 4'd1;
                          test_percep_done <= test_percep_done + 4'd1;
                  end else begin
                          stop = 1'b0; 
                          input_index = input_index + 0;
                          epoch_counter = epoch_counter + 1;    
                          next_addr = 4'd5;    
                          percep_wt_1_reg = percep_wt_1_reg + 4'd0;
                          percep_wt_2_reg = percep_wt_2_reg + 4'd0;
                          percep_bias_reg = percep_bias_reg + 4'd0;
                          prev_wt1_update = prev_wt1_update + 4'd0;
                          prev_wt2_update = prev_wt2_update + 4'd0;
                          prev_bias_update = prev_bias_update + 4'd0;
                          y_in = y_in + 4'd0;
                          y = y + 4'd0;
                          test_percep_output <= test_percep_output + 4'b0;
                          test_percep_result <= test_percep_result + 4'd1;
                          test_percep_done <= test_percep_done + 4'd1;
                  end
                end
         4'd5: begin
                          percep_wt_1_reg = percep_wt_1_reg + 4'd0;
                          percep_wt_2_reg = percep_wt_2_reg + 4'd0;
                          percep_bias_reg = percep_bias_reg + 4'd0;
                          prev_wt1_update  = wt1_update;
                          prev_wt2_update  = wt2_update;
                          prev_bias_update = bias_update;
                          next_addr = 4'd1;
                          input_index = input_index + 1;
                          stop = stop + 1'b0;
                          test_percep_output <= test_percep_output + 4'b0;
                          test_percep_result <= test_percep_result + 4'd1;
                          test_percep_done <= test_percep_done + 4'd1;
                  end
            default : begin
                          next_addr = next_addr + 4'd0;
                          percep_wt_1_reg = percep_wt_1_reg + 4'd0;
                          percep_wt_2_reg = percep_wt_2_reg + 4'd0;
                          percep_bias_reg = percep_bias_reg + 4'd0;
                          prev_wt1_update = prev_wt1_update + 4'd0;
                          prev_wt2_update = prev_wt2_update + 4'd0;
                          prev_bias_update = prev_bias_update + 4'd0;
                          stop = stop + 1'b0;
                          y_in = y_in + 4'd0;
                          y = y + 4'd0;
                          input_index = input_index + 0;
                          target = target + 4'd0;
                          wt1_update = wt1_update + 4'd0;
                          wt2_update = wt2_update + 4'd0;
                          bias_update = bias_update + 4'd0;
                          test_percep_output <= test_percep_output + 4'b0;
                          test_percep_result <= test_percep_result + 4'd1;
                          test_percep_done <= test_percep_done + 4'd1;
                  end
      endcase
   end
   assign percep_w1 = percep_wt_1_reg;
   assign percep_w2 = percep_wt_2_reg;
   assign percep_bias = percep_bias_reg;

   // Testing logic
   always @(posedge clk or negedge rst_n) begin
      if (!rst_n) begin
         test_percep_present_state <= 4'd0;
         test_percep_output <= 4'd0;
         test_percep_result <= 4'd0;
         test_percep_done <= 4'd0;
      end
   end

   assign test_percep_index = test_percep_present_state[3:0];

   assign y_in = test_percep_output;

   // Testing logic for comparison
   assign expected_percep_output = test_expected_output;

   assign test_calc = percep_w1 * test_percep_x1 + percep_w2 * test_percep_x2 + percep_bias;
   assign test_percep_output = (test_calc > threshold) ? 4'd1 : (test_calc >= -threshold && test_calc <= threshold) ? 4'd0 : -4'd1;

   assign test_percep_result = (test_percep_output == expected_percep_output) ? 4'd1 : 4'd0;

   // Mark test_percep_done when the test index reaches the terminal value for a gate
   assign test_percep_done = (test_percep_index == (gate_select ? 4 : 8));

endmodule

module perceptron_gates (
   input  logic clk,// Posedge clock
   input  logic rst_n,// Negedge reset
   input  logic signed [3:0] x1, // First Input of the Perceptron
   input  logic signed [3:0] x2, // Second Input of the Perceptron
   input  logic learning_rate, // Learning rate (alpha)
   input  logic signed [3:0] threshold, // Threshold value
   input  logic [1:0] gate_select, // Gate selection for target values
   output logic signed [3:0] percep_w1, // Trained Weight 1 
   output logic signed [3:0] percep_w2, // Trained Weight 2
   output logic signed [3:0] percep_bias, // Trained Bias
   output logic [3:0] present_addr, // Current address in microcode ROM
   output logic stop, // Condition to indicate no learning has occurred(i.e. no weight change between iterations)
   output logic [2:0] input_index,// Vector to track the selection of target for a given input combination for a gate
   output logic signed [3:0] y_in, // Calculated Response
   output logic signed [3:0] y, // Calculated Response obtained by comparing y_in against a threshold value
   output logic signed [3:0] prev_percep_wt_1,//Value of Weight 1 during a previous iteration
   output logic signed [3:0] prev_percep_wt_2,//Value of Weight 2 during a previous iteration
   output logic signed [3:0] prev_percep_bias // Value of Bias during a previous iteration
);

   logic [7:0] microcode_rom [0:5];
   logic [3:0]  next_addr;
   logic [3:0]  train_action;
   logic [3:0]  microcode_addr;
   logic [15:0] microinstruction;
   logic signed [3:0] t1, t2, t3, t4;

   gate_target dut (
       .gate_select(gate_select),
       .o_1(t1),
       .o_2(t2),
       .o_3(t3),
       .o_4(t4)
   );

   logic signed [3:0] percep_wt_1_reg;
   logic signed [3:0] percep_wt_2_reg;
   logic signed [3:0] percep_bias_reg;

   logic signed [3:0] target;
   logic signed [3:0] prev_wt1_update;
   logic signed [3:0] prev_wt2_update;
   logic signed [3:0] prev_bias_update;

   logic signed [3:0] wt1_update;
   logic signed [3:0] wt2_update;
   logic signed [3:0] bias_update;
   logic [7:0] epoch_counter;

   assign  prev_percep_wt_1 = prev_wt1_update;
   assign  prev_percep_wt_2 = prev_wt2_update;
   assign  prev_percep_bias = prev_bias_update;

   always@(*) begin
      microinstruction = microcode_rom[microcode_addr];
      next_addr        = microinstruction[7:4];
      train_action     = microinstruction[3:0];
   end

   always_ff @(posedge clk or negedge rst_n) begin
      if (!rst_n) begin
         present_addr    <= 4'd0;
         microcode_addr  <= 4'd0;
         percep_wt_1_reg <= 4'd0;
         percep_wt_2_reg <= 4'd0;
         percep_bias_reg <= 4'd0;
         input_index     <= 2'd0;
         stop            <= 1'b0;
      end else begin
         present_addr    <= next_addr;
         microcode_addr  <= present_addr;
      end
   end

   always_comb begin
      case(train_action)
          4'd0 : begin 
                 // Initialize weights and bias to zero
                 percep_wt_1_reg = 4'd0;
                 percep_wt_2_reg = 4'd0;
                 percep_bias_reg = 4'd0;
                 stop            <= 1'b0;
               end
          4'd1 : begin 
                 // Compute y_in using current weights and inputs
                 y_in = percep_bias_reg + (x1 * percep_wt_1_reg) + (x2 * percep_wt_2_reg);
                 // Compute y based on threshold
                 if (y_in > threshold)
                    y = 4'd1;
                 else if (y_in >= -threshold && y_in <= threshold)
                    y = 4'd0;
                 else
                    y = -4'd1;
               end
          4'd2 : begin 
                 // Select target based on input_index
                 case(input_index)
                   2'd0: target = t1;
                   2'd1: target = t2;
                   2'd2: target = t3;
                   2'd3: target = t4;
                 default: input_index <= 2'd0;
                     target = 4'd0;
                 end
               end
          4'd3 : begin 
                 // Update weights and bias if error occurred
                 if (y != target) begin
                    wt1_update = learning_rate * x1 * target;
                    wt2_update = learning_rate * x2 * target;
                    bias_update = learning_rate * target;
                 end else begin
                    wt1_update = 4'd0;
                    wt2_update = 4'd0;
                    bias_update = 4'd0;
                 end
               end
          4'd4 : begin 
                 // Check if weight changes occurred
                 if (wt1_update == prev_wt1_update && wt2_update == prev_wt2_update && bias_update == prev_bias_update)
                    stop = 1'b1; // No weight change, stop training
                 else
                    stop = 1'b0; // Weight change, continue training
               end
          4'd5 : begin 
                 // Update previous weights and bias
                 prev_wt1_update = wt1_update;
                 prev_wt2_update = wt2_update;
                 prev_bias_update = bias_update;
                 input_index <= input_index + 4'd1;
               end
               // No change in other signals
               y_in <= y;
               prev_percep_wt_1 <= percep_wt_1_reg;
               prev_percep_wt_2 <= percep_wt_2_reg;
               prev_percep_bias <= percep_bias_reg;
               // No change in other signals
               stop <= stop;
               input_index <= input_index;
               epoch_counter <= epoch_counter + 4'd1;
               y <= y;
               next_addr <= next_addr;
               microcode_addr <= next_addr;
               // No change in other signals
               stop <= stop;
               y_in <= y_in;
      endcase
   end

endmodule

output.rtl/cvdp_copilot_perf_counters.sv:
module perf_counter #(parameter W = 8) (
    input clk,
    input reset,
    input sw_req_i,
    input cpu_trig_i,
    output reg signed [W-1:0] p_count_o
);

    // Internal flip-flop to hold the counter value
    reg [W-1:0] count_q;

    // Counter increment logic
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            count_q <= 0;
        end else if (cpu_trig_i) begin
            count_q <= count_q + 1'b1;
        end
    end

    // Software read logic
    always @(posedge clk) begin
        if (sw_req_i) begin
            // Output the count value and reset the counter
            p_count_o <= count_q;
            count_q <= 0;
        end
    end

endmodule

