module run_length
#(
    parameter DATA_WIDTH = 8                        // Width of the output run-length counter
)
(
    input wire clk,                                 // Clock signal      
    input wire reset_n,                             // Active-low reset signal     
    input wire data_in,                             // Input data stream
    output reg  data_out,                           // Output data to indicate the previous data_in
    output reg [$clog2(DATA_WIDTH):0] run_value,    // Output the run length value 
    output reg valid                                // Output valid flag for run length 

);
    reg [$clog2(DATA_WIDTH):0] run_length;
    reg [DATA_WIDTH-1:0] run_value;
    reg prev_data_in;

    always @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            run_length   <= 'b0;           
            run_value    <= 'b0;	       
            prev_data_in <= 1'b0;			               
            valid       <= 1'b0;
        end
        else begin
            prev_data_in <= data_in;
            if (data_in !== prev_data_in) begin
                run_length <= 1;
                data_out <= prev_data_in;
                valid <= 1'b1;
            end
            else if (run_length == (2**DATA_WIDTH - 1)) begin
                run_value <= run_length;
                run_length <= 1;
                valid <= 1'b0;
            end
            else begin
                run_length <= run_length + 1;
            end
        end
    end
endmodule

module parallel_run_length(
    parameter DATA_WIDTH = 8,                        // Width of the output run-length counter
    parameter NUM_STREAMS = 4                        // Number of parallel input streams
);

    input wire clk,                                 // Clock signal      
    input wire reset_n,                             // Active-low reset signal     
    input wire [NUM_STREAMS-1:0] data_in,            // Parallel input data streams
    output reg [NUM_STREAMS-1:0] data_out,          // Output last value of each data stream when a valid run length is computed
    output reg [(NUM_STREAMS * ($clog2(DATA_WIDTH)+1)) - 1:0] run_value, // Output run length for each stream
    output reg [NUM_STREAMS-1:0] valid               // Indicates when a new run length is available for each stream

    // Internal registers
    reg [$clog2(DATA_WIDTH)-1:0] run_length [NUM_STREAMS-1:0]; // Run length counters for each stream
    reg [NUM_STREAMS-1:0] prev_data_in;             // Previous data value for each stream

    // Always block for synchronous operations
    always @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            for (int i = 0; i < NUM_STREAMS; i++) begin
                run_length[i] <= 0;
                valid[i] <= 0;
                data_out[i] <= 0;
            end
        end else begin
            for (int i = 0; i < NUM_STREAMS; i++) begin
                if (stream_enable[i]) begin
                    if (data_in[i] == prev_data_in[i]) begin
                        if (run_length[i] == (DATA_WIDTH)) begin
                            valid[i] <= 1;
                            data_out[i] <= prev_data_in[i];
                            run_length[i] <= run_length[i] + 1'b1;
                        end else if (run_length[i] < (DATA_WIDTH)) begin
                            valid[i] <= 1;
                            run_length[i] <= run_length[i] + 1'b1;
                        end else begin
                            valid[i] <= 1;
                            run_length[i] <= 1'b1;
                        end
                    end else begin
                        valid[i] <= 1;
                        data_out[i] <= prev_data_in[i];
                        run_length[i] <= 1'b1;
                    end
                end else begin
                    run_length[i] <= 0;
                    valid[i] <= 0;
                    data_out[i] <= 0;
                end
                prev_data_in[i] <= data_in[i];
            end
        end
    end

endmodule

output.rtl/scrambler.sv:
module scrambler #(
    parameter DATA_WIDTH = 128   // Width of input data
) (
    input  logic                  clk,        // Clock signal
    input  logic                  rst_n,      // Active-low reset
    input  logic [DATA_WIDTH-1:0] data_in,    // Input data
    input  logic [3:0]            mode,       // Mode to select polynomial
    output logic [DATA_WIDTH-1:0] data_out    // Scrambled data
);

    localparam LFSR_WIDTH = 16;    // Width of the LFSR
    localparam [LFSR_WIDTH-1:0] LFSR_INIT = {1'b0,1'b1,{(LFSR_WIDTH-2){1'b0}}};
    // LFSR registers and feedback logic
    logic [LFSR_WIDTH-1:0] lfsr;
    logic feedback;

    // Polynomial selection based on mode
    always_comb begin
        case (mode)
            4'b0000: feedback = lfsr[LFSR_WIDTH-16] ^ lfsr[LFSR_WIDTH-15];                // Mode 0: ( x^{16} + x^{15} + 1 )
            4'b0001: feedback = lfsr[LFSR_WIDTH-16] ^ lfsr[LFSR_WIDTH-14];                // Mode 1: ( x^{16} + x^{14} + 1 )
            4'b0010: feedback = lfsr[LFSR_WIDTH-16] ^ lfsr[LFSR_WIDTH-8] ^ lfsr[1];      // Mode 2: ( x^{16} + x^{8} + x + 1 )
            4'b0011: feedback = lfsr[LFSR_WIDTH-16] ^ lfsr[LFSR_WIDTH-8];                // Mode 3: ( x^{16} + x^{8} + 1 )
            4'b0100: feedback = lfsr[LFSR_WIDTH-16] ^ lfsr[LFSR_WIDTH-13] ^ lfsr[4];      // Mode 4: ( x^{16} + x^{13} + x^2 + 1 )
            4'b0101: feedback = lfsr[LFSR_WIDTH-16] ^ lfsr[LFSR_WIDTH-12];                // Mode 5: ( x^{16} + x^{12} + 1 )
            4'b0110: feedback = lfsr[LFSR_WIDTH-16] ^ lfsr[3] ^ lfsr[0];                 // Mode 6: ( x^{16} + x^3 + x + 1 )
            4'b0111: feedback = lfsr[LFSR_WIDTH-16] ^ lfsr[LFSR_WIDTH-11] ^ lfsr[4];      // Mode 7: ( x^{16} + x^{11} + x^4 + 1 )
            default: feedback = lfsr[LFSR_WIDTH-16];                                     // Default:( x^{16} + 1 )
        endcase
    end

    // Synchronization of mode signal
    logic sync_mode;
    assign sync_mode = (~rst_n) & mode;

    // LFSR shift logic
    always_ff @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            lfsr <= LFSR_INIT; // Initialize LFSR with a fixed value
        end else begin
            lfsr <= {lfsr[LFSR_WIDTH-2:0], feedback};
        end
    end

    // Scramble data block
    genvar i;
    generate
        for (i = 0; i < DATA_WIDTH; i++) begin
            assign data_out[i] = data_in[i] ^ lfsr[i % LFSR_WIDTH];
        end
    endgenerate

endmodule

