logic [DATA_WIDTH-1:0] in_data_reg [SUB_BLOCKS-1:0];
logic [DATA_WIDTH-1:0] out_data_intra_block [SUB_BLOCKS-1:0];
logic [DATA_WIDTH-1:0] out_data_intra_block_reg [SUB_BLOCKS-1:0];
logic [DATA_WIDTH-1:0] out_data_aux [SUB_BLOCKS-1:0];
logic start_intra;

always_ff @(posedge clk or negedge rst_n ) begin
   if(!rst_n) begin
      counter_sub_blocks <= {NBW_COUNTER{1'b0}};
      start_intra <= 0;
      for(int i = 0; i < SUB_BLOCKS; i++) begin
         in_data_reg[i] <= {DATA_WIDTH{1'b0}};
      end
   end
   else begin
      if(i_valid) begin
         in_data_reg[counter_sub_blocks] <= in_data;

         if(counter_sub_blocks == SUB_BLOCKS) begin
            counter_sub_blocks <= {NBW_COUNTER{1'b0}};
         end
         else begin
            start_intra <= 0;
            counter_sub_blocks <= counter_sub_blocks + 1;
         end
      end
      else if(counter_sub_blocks == SUB_BLOCKS) begin
         start_intra        <= 1;
         counter_sub_blocks <= {NBW_COUNTER{1'b0}};
      end
   end
end

genvar k;
generate 
   for(k = 0; k < SUB_BLOCKS; k++) begin
      intra_block uu_intra_block (
         .in_data(in_data_reg[k]),
         .out_data(out_data_intra_block[k])
      );
   end
endgenerate

always_ff @(posedge clk or negedge rst_n) begin
   if(!rst_n) begin
      for(int i = 0; i < SUB_BLOCKS; i++) begin
         out_data_intra_block_reg[i] <= {DATA_WIDTH{1'b0}};
      end
   end
   else begin
      if(start_intra) begin
         for(int i = 0; i < SUB_BLOCKS; i++) begin
            out_data_intra_block_reg[i] <= out_data_intra_block[i];
         end
      end
   end
end

always_ff @(posedge clk or negedge rst_n) begin
   if(!rst_n) begin
      counter_sub_out <= {NBW_COUNTER_SUB_OUT{1'b1}};
      out_data        <= {DATA_WIDTH{1'b0}};
      for(int i = 0; i < SUB_BLOCKS; i++) begin
         out_data_aux[i] <= {DATA_WIDTH{1'b0}};
      end      
   end
   else begin
      if(start_intra) begin
         for(int i = 0; i < 32; i++) begin
            out_data_aux[0][(i+1)*CHUNK-1-:CHUNK] = out_data_intra_block_reg[i%4][((i+1)*CHUNK)-1-:CHUNK];
            out_data_aux[1][(i+1)*CHUNK-1-:CHUNK] = out_data_intra_block_reg[i%4][(((i+1)%OUT_CYCLES+1)*CHUNK)-1-:CHUNK];
            out_data_aux[2][(i+1)*CHUNK-1-:CHUNK] = out_data_intra_block_reg[i%4][(((i+2)%OUT_CYCLES+1)*CHUNK)-1-:CHUNK];
            out_data_aux[3][(i+1)*CHUNK-1-:CHUNK] = out_data_intra_block_reg[i%4][(((i+3)%OUT_CYCLES+1)*CHUNK)-1-:CHUNK];
         end
         counter_sub_out <= counter_sub_out + 1;
         out_data        <= out_data_aux[counter_sub_out];
      end
   end
end

endmodule

input.rtl/intra_block.sv:
module intra_block #(
    parameter ROW_COL_WIDTH = 16,
    parameter DATA_WIDTH = ROW_COL_WIDTH*ROW_COL_WIDTH
)(
    input logic [DATA_WIDTH-1:0] in_data,  // Input: 256 bits
    output logic [DATA_WIDTH-1:0] out_data // Output: 256 bits rearranged
);

    // Temporary storage for intermediate calculations
    logic [3:0] r_prime [0:255]; // Row index for each bit
    logic [3:0] c_prime [0:255]; // Column index for each bit

    logic [ROW_COL_WIDTH-1:0] prev_out_data [ROW_COL_WIDTH-1:0];

    always_comb begin
       for(int i = 0; i < 256; i++) begin
         if (i < 128) begin
            r_prime[i] = (i - 2 * (i / 16)) % 16;
            c_prime[i] = (i -     (i / 16)) % 16;
         end
         else begin
            r_prime[i] = (i - 2 * (i / 16) - 1) % 16;
            c_prime[i] = (i - (i / 16) - 1) % 16;
         end
       end
    end
    int j, k;
    logic [7:0] output_index[256];
    always_comb begin
      for (j = 0; j < 256; j++) begin
           output_index[j] = r_prime[j] * 16 + c_prime[j];
           out_data[j]     = in_data[output_index[j]];
        end
    end
endmodule

output.rtl/intra_block.sv:
module intra_block #(
    parameter ROW_COL_WIDTH = 16,
    parameter DATA_WIDTH = ROW_COL_WIDTH * ROW_COL_WIDTH
)(
    input logic [DATA_WIDTH-1:0] in_data, // Input: 256 bits
    output logic [DATA_WIDTH-1:0] out_data // Output: 256 bits rearranged
);

    logic [ROW_COL_WIDTH-1:0] r_prime[255];
    logic [ROW_COL_WIDTH-1:0] c_prime[255];

    // Calculate row and column indices in one loop
    always_comb begin
        integer j;
        for (j = 0; j < 256; j++) begin
            if (j < ROW_COL_WIDTH) begin
                r_prime[j] = j / ROW_COL_WIDTH;
                c_prime[j] = j % ROW_COL_WIDTH;
            end else begin
                r_prime[j] = (j - ROW_COL_WIDTH) / ROW_COL_WIDTH;
                c_prime[j] = (j - ROW_COL_WIDTH) % ROW_COL_WIDTH;
            end
        end
    end

    always_comb begin
        integer j;
        for (j = 0; j < 256; j++) begin
            out_data[j] = in_data[r_prime[j] * ROW_COL_WIDTH + c_prime[j]];
        end
    end

endmodule

output.rtl/sdram_controller.sv:
module sdram_controller (
    input clk,
    input reset,
    input [24:0] addr,
    input [15:0] data_in,
    output reg [15:0] data_out,
    output reg sdram_clk,
    output reg sdram_cke,
    output reg sdram_cs,
    output reg sdram_ras,
    output reg sdram_cas,
    output reg sdram_we,
    output reg sdram_addr,
    output reg sdram_ba,
    output [15:0] sdram_dq,
    output [15:0] dq_out
);

    // State declaration
    typedef enum logic [1:0] {
        INIT,
        IDLE,
        ACTIVATE,
        READ,
        WRITE,
        REFRESH
    } state_t;

    state_t current_state, next_state;

    // State register
    reg [1:0] state_reg;

    // Comparator for IDLE timeout
    reg [31:0] idle_counter;

    // FSM implementation
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            current_state <= INIT;
            state_reg <= 2'b00;
            idle_counter <= 0;
        end else begin
            idle_counter <= idle_counter + 1;
            if (idle_counter >= 1024) begin
                current_state <= REFRESH;
                idle_counter <= 0;
            end else begin
                current_state <= state_reg;
            end
        end
    end

    // State transition logic
    always @(*) begin
        case (current_state)
            INIT: begin
                state_reg <= 2'b01;
            end
            IDLE: begin
                if (data_in) begin
                    if (read) begin
                        state_reg <= ACTIVATE;
                    end else if (write) begin
                        state_reg <= ACTIVATE;
                    end
                end else if (idle_counter >= 1024) begin
                    state_reg <= REFRESH;
                    idle_counter <= 0;
                end
            end
            ACTIVATE: begin
                sdram_cs <= 1;
                sdram_ras <= 1;
                sdram_cas <= 1;
                sdram_we <= 0;
                sdram_addr <= addr;
                sdram_ba <= 1;
            end
            READ: begin
                sdram_cs <= 1;
                sdram_cke <= 1;
                sdram_ras <= 0;
                sdram_cas <= 1;
                sdram_we <= 0;
                sdram_addr <= addr;
                sdram_ba <= 1;
                next_state <= READ;
            end
            WRITE: begin
                sdram_cs <= 1;
                sdram_cke <= 1;
                sdram_ras <= 0;
                sdram_cas <= 1;
                sdram_we <= 1;
                sdram_addr <= addr;
                sdram_ba <= 1;
                next_state <= WRITE;
            end
            REFRESH: begin
                sdram_cs <= 1;
                sdram_cke <= 1;
                sdram_ras <= 1;
                sdram_cas <= 1;
                sdram_we <= 0;
                sdram_addr <= addr;
                sdram_ba <= 1;
                next_state <= IDLE;
            end
            default: next_state <= IDLE;
        endcase
    end

    // State transition logic
    always @(posedge clk) begin
        if (current_state != next_state) begin
            state_reg <= next_state;
        end
    end

    // Output logic for READ and WRITE operations
    always @(state_reg) begin
        case (state_reg)
            READ: begin
                data_out <= sdram_dq;
            end
            WRITE: begin
                dq_out <= data_in;
            end
            default: data_out <= 0;
            dq_out <= 0;
        endcase
    end

endmodule

output.rtl/alu_seq.v:
module alu_seq (
    input i_clk,          // Clock signal
    input i_rst_b,        // Active-low asynchronous reset
    input [3:0] i_operand_a, // 4-bit input operand A
    input [3:0] i_operand_b, // 4-bit input operand B
    input [2:0] i_opcode,    // 3-bit operation code
    input [7:0] i_key_in,    // 8-bit security key input
    output reg [7:0] o_result // 8-bit operation result
);

    // Internal configurable security key
    reg [7:0] p_key = 8'hAA;

    // State register to hold the result
    reg [7:0] temp_result;

    // Comparator for the key
    always @ (i_key_in) begin
        if (i_key_in == p_key) begin
            // Key matches, perform operation
            if (i_opcode == 3'b000) begin
                temp_result = i_operand_a + i_operand_b;
            end else if (i_opcode == 3'b001) begin
                temp_result = i_operand_a - i_operand_b;
            end else if (i_opcode == 3'b010) begin
                temp_result = i_operand_a * i_operand_b;
            end else if (i_opcode == 3'b011) begin
                temp_result = i_operand_a & i_operand_b;
            end else if (i_opcode == 3'b100) begin
                temp_result = i_operand_a | i_operand_b;
            end else if (i_opcode == 3'b101) begin
                temp_result = ~i_operand_a;
            end else if (i_opcode == 3'b110) begin
                temp_result = i_operand_a ^ i_operand_b;
            end else if (i_opcode == 3'b111) begin
                temp_result = ~(i_operand_a ^ i_operand_b);
            end
        end else begin
            // Key does not match, result is 0
            temp_result = 8'b0;
        end
    end

    // Asynchronous reset
    always @ (posedge i_clk or negedge i_rst_b) begin
        if (!i_rst_b) begin
            o_result <= 8'b0;
        end else begin
            o_result <= temp_result;
        end
    end

endmodule

output.rtl/secure_read_write_bus_interface.v:
module secure_read_write_bus_interface #(
    parameter p_data_width = 8,
    parameter p_addr_width = 8,
    parameter p_configurable_key = 8'hAA
) (
    input wire i_capture_pulse,
    input wire i_reset_bar,
    input wire [p_addr_width-1:0] i_addr,
    input wire [p_data_width-1:0] i_data_in,
    input wire i_key_in,
    input wire i_read_write_enable,
    output reg o_data_out,
    output reg o_error
);

    reg [p_data_width-1:0] temp_data_out;
    reg temp_error;

    // Internal state register
    reg [p_addr_width-1:0] temp_addr;
    reg temp_key;

    // Default values
    always @(posedge i_capture_pulse or posedge i_reset_bar) begin
        if (i_reset_bar) begin
            o_data_out <= 0;
            o_error <= 0;
            temp_data_out <= 0;
            temp_error <= 0;
            temp_addr <= 0;
            temp_key <= p_configurable_key;
        end else begin
            if (i_read_write_enable) begin
                temp_addr <= i_addr;
                temp_key <= i_key_in;
            end
        end
    end

    // Authorization check
    always @(posedge i_capture_pulse) begin
        if (i_read_write_enable) begin
            if (temp_key == p_configurable_key) begin
                temp_data_out <= i_data_in;
                o_error <= 0;
            end else begin
                temp_data_out <= 0;
                o_error <= 1;
            end
        end else begin
            temp_data_out <= 0;
            o_error <= 0;
        end
    end

    // Output assignment
    assign o_data_out = temp_data_out;
    assign o_error = temp_error;

endmodule

output.rtl/secure_read_write_register_bank.v:
module secure_read_write_register_bank #(
    parameter p_addr_width = 8,
    parameter p_data_width = 8,
    parameter p_unlock_code_0 = 0xAB,
    parameter p_unlock_code_1 = 0xCD
) (
    input wire [p_addr_width-1:0] i_addr,
    input wire [p_data_width-1:0] i_data_in,
    input wire i_read_write_enable,
    input wire i_capture_pulse,
    input wire i_rst_n,
    output reg [p_data_width-1:0] o_data_out
);

    // Unlock state
    reg [p_data_width-1:0] unlock_status;

    // Unlock sequence completion signal
    reg unlock_sequence_complete;

    // Unlock sequence process
    always @(posedge i_capture_pulse or posedge i_rst_n) begin
        if (i_rst_n) begin
            unlock_status <= 0;
            unlock_sequence_complete <= 0;
        end else if (i_capture_pulse) begin
            if (unlock_status == 0) begin
                if (i_addr == 0) begin
                    unlock_status <= p_unlock_code_0;
                end else if (i_addr == 1) begin
                    unlock_status <= p_unlock_code_1;
                end
            end
            if (unlock_status == p_unlock_code_0 && unlock_status == p_unlock_code_1) begin
                unlock_sequence_complete <= 1;
            end
        end
    end

    // Read and write operations
    always @(posedge i_capture_pulse) begin
        if (i_rst_n) begin
            o_data_out <= 0;
        end else if (i_read_write_enable) begin
            if (unlock_sequence_complete) begin
                if (i_addr == 0 || i_addr == 1) begin
                    o_data_out <= 0; // Write-only addresses
                end else begin
                    o_data_out <= i_data_in;
                end
            end
        end
    end

endmodule

output.rtl/secure_variable_timer.v:
module secure_variable_timer (
    input wire i_clk,           // Clock signal (rising-edge triggered)
    input wire i_rst_n,         // Active-low synchronous reset signal
    input wire i_data_in,       // Serial data input
    output reg [3:0] o_time_left, // 4-bit output showing remaining time during counting phase
    output reg o_processing,    // Asserted high when the timer is actively counting
    output reg o_completed,     // Asserted high when the timer completes its delay
    input wire i_ack            // Acknowledgment signal to reset after completion
);

    // Internal registers
    reg [3:0] delay;            // Holds the 4-bit delay value
    reg [9:0] counter;          // Counter for the total cycle count
    reg [3:0] time_left;        // Temporary register to hold the current time left

    // State definitions
    typedef enum logic [1:0] {IDLE, CONFIGURE, COUNTING, DONE} State_t;
    reg [1:0] state, next_state;

    // State transition logic
    always @(posedge i_clk or negedge i_rst_n) begin
        if (!i_rst_n) begin
            state <= IDLE;
            counter <= 0;
            time_left <= 0;
        end else begin
            state <= next_state;
        end
    end

    // State machine logic
    always @(state or i_data_in or i_ack) begin
        case (state)
            IDLE: begin
                if (i_data_in == 4'b1101) begin
                    delay <= i_data_in;
                    next_state = CONFIGURE;
                end else begin
                    next_state = IDLE;
                end
            end
            CONFIGURE: begin
                if (i_data_in == 4'b0000) begin
                    next_state = COUNTING;
                end else begin
                    next_state = IDLE;
                end
            end
            COUNTING: begin
                counter <= counter + 1;
                if (counter >= delay + 999) begin
                    counter <= 0;
                    time_left <= delay;
                    o_time_left <= time_left;
                    o_processing <= 1'b1;
                    next_state = DONE;
                end else begin
                    time_left <= time_left - 1;
                    o_time_left <= time_left;
                end
            end
            DONE: begin
                if (i_ack) begin
                    o_completed <= 1'b1;
                    next_state = IDLE;
                end else begin
                    next_state = IDLE;
                end
            end
        end
    end

endmodule

output.rtl/binary_to_one_hot_decoder_sequential:
module binary_to_one_hot_decoder_sequential #(
    parameter BINARY_WIDTH = 5,
    parameter OUTPUT_WIDTH = 32
) (
    input [BINARY_WIDTH-1:0] i_binary_in,
    input i_clk,
    input i_rstb,
    output reg [OUTPUT_WIDTH-1:0] o_one_hot_out
);

    // Sequential register to hold the one-hot encoded output
    reg [OUTPUT_WIDTH-1:0] seq_register;

    // Combinational logic to set the one-hot encoded output
    always @(posedge i_clk or posedge i_rstb) begin
        if (i_rstb) begin
            seq_register <= 0;
        end else begin
            seq_register <= {seq_register[OUTPUT_WIDTH-1-i_binary_in], 1'b0};
        end
    end

    // Output assignment
    assign o_one_hot_out = seq_register;

endmodule

output.rtl/serial_in_parallel_out_8bit.sv:
module serial_in_parallel_out_8bit(
    input clock,
    input serial_in,
    output reg [7:0] parallel_out
);

    // State variable to keep track of the shift register
    reg [7:0] shift_reg;

    // Synchronous process triggered on the positive edge of the clock
    always @(posedge clock) begin
        // Shift the register to the left
        shift_reg <= {shift_reg[6:0], serial_in};
        // Update the parallel output with the new contents of the shift register
        parallel_out <= shift_reg;
    end

    // Initialize the shift register to all 'x' (unknown) on reset
    initial begin
        shift_reg = 8'bx;
    end

endmodule

