            buffer_ready <= 0;
        end else begin
            if (valid_i && !buffer_ready) begin
                buffer_reg <= data_i;
                buffer_valid <= 1;
                buffer_ready <= ready_i;
            end
            data_o <= buffer_reg;
            valid_o <= buffer_valid;
            ready_o <= buffer_ready;
