    input  wire                [N*WIDTH-1:0]  in_data,
    output reg                 done,
    output reg [N*WIDTH-1:0]   out_data
);

    // Internal registers to hold the array
    reg [WIDTH-1:0] array [0:N-1];

    // FSM states
    localparam IDLE    = 2'd0;
    localparam SORTING = 2'd1;
    localparam DONE    = 2'd2;

    reg [1:0]  state, next_state;

    // Variables for insertion sort indexing
    reg [$clog2(N)-1:0] i;  // Index for the element being inserted
    reg [$clog2(N)-1:0] j;  // Index for the position in the sorted portion

    // Wires for comparison and shift
    wire [WIDTH-1:0] val_j;
    wire [WIDTH-1:0] val_j1;

    assign val_j  = array[j];
    assign val_j1 = array[j+1];

    // FSM: Next state logic
    always @(*) begin
        next_state = state;
        case (state)
            IDLE: begin
                if (start)
                    next_state = SORTING;
            end
            SORTING: begin
                // Transition to DONE once all elements are inserted
                if (i == N-1)
                    next_state = DONE;
            end
            DONE: begin
                next_state = IDLE;
            end
            default: begin
                next_state = IDLE;
            end
        endcase
    end

    // FSM: Output and counter updates
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= IDLE;
            i <= 0;
            j <= 0;
        end else begin
            state <= next_state;

            case (state)
                IDLE: begin
                    done <= 0;
                    if (start) begin
                        // Load the array from in_data
                        for (int k = 0; k < N; k = k + 1) begin
                            array[k] <= in_data[(k+1)*WIDTH-1 -: WIDTH];
                        end
                        i <= 0;
                        j <= 0;
                    end
                end

                SORTING: begin
                    // Insert the current element into the sorted portion
                    if (j == 0) begin
                        array[j] <= val_j1;
                        j <= 1;
                    end else begin
                        // Compare the current element with the last element in the sorted portion
                        if (val_j > val_j1) begin
                            // If the current element is greater, shift the sorted elements to the right
                            for (int k = N-1; k > j; k = k - 1) begin
                                array[k] <= array[k-1];
                            end
                            array[j] <= val_j1;
                        end else begin
                            j <= j + 1;
                        end
                    end
                end

                DONE: begin
                    // Sorting complete
                    done <= 1;
                    // Output the sorted data
                    for (int m = 0; m < N; m = m + 1) begin
                        out_data[(m+1)*WIDTH-1 -: WIDTH] <= array[m];
                    end
                end
                default: begin
                end
            endcase
        end
    end

endmodule

module sorting_engine #(
    parameter N = 8,     
    parameter WIDTH = 8  
)(
    input  wire                clk,
    input  wire                rst,
    input  wire                start,
    input  wire [N*WIDTH-1:0]  in_data,
    output reg                 done,
    output reg [N*WIDTH-1:0]   out_data
);
    localparam IDLE = 2'd0,
               LOAD = 2'd1,
               SORT = 2'd2,
               DONE = 2'd3;

    reg [1:0]  state, next_state;
    reg [WIDTH-1:0] data_array [0:N-1];
    reg [$clog2(N+1)-1:0] pass_cnt;
    reg [$clog2(N/2+1)-1:0] pair_idx;

    wire [$clog2(N/2+1)-1:0] pairs_in_this_pass;
    assign pairs_in_this_pass = (pass_cnt[0] == 1'b0) ? (N/2) : ( (N/2) > 0 ? (N/2) - 1 : 0 );

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= IDLE;
            pair_idx <= 0;
            pass_cnt <= 0;
            out_data <= {N{1'b0}};
            done <= 0;
        end else if (start) begin
            state <= LOAD;
            pair_idx <= 0;
            pass_cnt <= 0;
            data_array <= in_data;
            done <= 0;
        end else if (state == IDLE) begin
            state <= LOAD;
        end else if (state == LOAD) begin
            pair_idx <= $random;
            state <= SORT;
        end else if (state == SORT) begin
            if (pair_idx == pairs_in_this_pass) begin
                if (pass_cnt == N - 1) begin
                    state <= DONE;
                end else begin
                    state <= SORT;
                    pass_cnt <= pass_cnt + 1;
                    pair_idx <= pair_idx + (N/2) - (pass_cnt - 1) * (N/2);
                end
            end else begin
                int i = pair_idx;
                int j = pair_idx + 1;
                if (data_array[i] > data_array[j]) begin
                    wire temp = data_array[i];
                    data_array[i] = data_array[j];
                    data_array[j] = temp;
                end
                state <= SORT;
                pair_idx <= pair_idx + 1;
            end
        end else if (state == DONE) begin
            state <= IDLE;
            out_data <= data_array;
            done <= 1;
        end
    end
endmodule

// Insert code here to implement the combinational logic for the FSM of the Counting sort algorithm.
always @(*) begin
    // Transition from S_IDLE to S_LOAD_INPUT
    if (current_state == S_IDLE && start && !rst) begin
        current_state <= S_LOAD_INPUT;
        load_cnt <= 0;
        for (i = 0; i < N; i = i + 1) begin
            data_array[i] <= in_data[i*WIDTH +: WIDTH];
        end
    end

    // Transition from S_LOAD_INPUT to S_FIND_MAX
    if (current_state == S_LOAD_INPUT && start && !rst) begin
        current_state <= S_FIND_MAX;
        find_cnt <= 0;
        max_val <= 0;
        for (i = 0; i < N; i = i + 1) begin
            val = data_array[i];
            if (val > max_val) begin
                max_val <= val;
            end
        end
    end

    // Transition from S_FIND_MAX to S_COUNT
    if (current_state == S_FIND_MAX && start && !rst) begin
        current_state <= S_COUNT;
        count_cnt <= 0;
        for (i = 0; i < (1<<WIDTH); i = i + 1) begin
            count_array[i] <= 0;
        end
        for (i = 0; i < N; i = i + 1) begin
            val = data_array[i];
            count_array[val] <= count_array[val] + 1;
        end
    end

    // Transition from S_COUNT to S_PREFIX_SUM
    if (current_state == S_COUNT && start && !rst) begin
        current_state <= S_PREFIX_SUM;
        prefix_cnt <= 0;
        for (i = 0; i < (1<<WIDTH); i = i + 1) begin
            prefix_cnt[i] <= count_array[i];
        end
    end

    // Transition from S_PREFIX_SUM to S_BUILD_OUTPUT
    if (current_state == S_PREFIX_SUM && start && !rst) begin
        current_state <= S_BUILD_OUTPUT;
        build_cnt <= 0;
    end

    // Transition from S_BUILD_OUTPUT to S_COPY_OUTPUT
    if (current_state == S_BUILD_OUTPUT && start && !rst) begin
        current_state <= S_COPY_OUTPUT;
        copy_cnt <= 0;
    end

    // Transition from S_COPY_OUTPUT to S_DONE
    if (current_state == S_COPY_OUTPUT && start && !rst) begin
        current_state <= S_DONE;
        next_done = 1'b1;
    end

    // Transition from S_IDLE to S_LOAD_INPUT
    if (current_state == S_IDLE && !start && !rst) begin
        current_state <= S_IDLE;
        done <= 1'b0;
        out_data <= {N*WIDTH{1'b0}};
    end

    // Transition from S_FIND_MAX to S_COUNT
    if (current_state == S_FIND_MAX && !start && !rst) begin
        current_state <= S_FIND_MAX;
        next_find_cnt <= 0;
        next_max_val <= max_val;
    end

    // Transition from S_COUNT to S_PREFIX_SUM
    if (current_state == S_COUNT && !start && !rst) begin
        current_state <= S_PREFIX_SUM;
        next_count_cnt <= count_cnt;
        next_prefix_cnt <= prefix_cnt;
    end

    // Transition from S_PREFIX_SUM to S_BUILD_OUTPUT
    if (current_state == S_PREFIX_SUM && !start && !rst) begin
        current_state <= S_BUILD_OUTPUT;
        next_build_cnt <= build_cnt;
    end

    // Transition from S_BUILD_OUTPUT to S_COPY_OUTPUT
    if (current_state == S_BUILD_OUTPUT && !start && !rst) begin
        current_state <= S_COPY_OUTPUT;
        next_copy_cnt <= copy_cnt;
    end

    // Transition from S_COPY_OUTPUT to S_DONE
    if (current_state == S_COPY_OUTPUT && !start && !rst) begin
        current_state <= S_DONE;
        next_done <= 1'b1;
    end
end

// Transition from S_DONE to S_IDLE
always @(posedge clk) begin
    if (current_state == S_DONE) begin
        current_state <= S_IDLE;
        next_state <= S_IDLE;
    end
end

// Update next_state combinational logic
always @(current_state, in_data, start, done) begin
    case({current_state, in_data, start, done})
        S_IDLE: next_state = S_IDLE;
        S_LOAD_INPUT: next_state = S_FIND_MAX;
        S_FIND_MAX: next_state = S_COUNT;
        S_COUNT: next_state = S_PREFIX_SUM;
        S_PREFIX_SUM: next_state = S_BUILD_OUTPUT;
        S_BUILD_OUTPUT: next_state = S_COPY_OUTPUT;
        S_COPY_OUTPUT: next_state = S_DONE;
        S_DONE: next_state = S_IDLE;
    endcase
end

// Update next_count_array and next_out_array
always @(current_state) begin
    case(current_state)
        S_COUNT: begin
            next_count_array = count_array;
        end
        S_PREFIX_SUM: begin
            next_prefix_cnt = prefix_cnt;
            for (i = 0; i < (1<<WIDTH); i = i + 1) begin
                next_count_array[i] = next_prefix_cnt[i];
            end
        end
        S_BUILD_OUTPUT: begin
            next_build_cnt = build_cnt;
            for (i = 0; i < N; i = i + 1) begin
                next_out_array[i] = out_array[i];
                for (j = 0; j < next_build_cnt; j = j + 1) begin
                    pos = next_count_array[i];
                    if (pos > 0) begin
                        next_out_array[i][pos-1] <= next_data_array[i][WIDTH-1];
                        pos = pos - 1;
                    end
                end
            end
        end
        S_COPY_OUTPUT: begin
            next_out_data = next_out_array;
        end
    endcase
end

// Update next_data_array
always @(current_state) begin
    case(current_state)
        S_LOAD_INPUT: begin
            next_data_array = data_array;
        end
        S_COUNT: begin
            next_data_array = {WIDTH{1'b0}};
        end
        S_BUILD_OUTPUT: begin
            next_data_array = next_out_array;
        end
    endcase
end

// Update next_max_val
always @(current_state) begin
    case(current_state)
        S_FIND_MAX: begin
            next_max_val = max_val;
        end
    end
end

// Update next_load_cnt, next_find_cnt, next_count_cnt, next_prefix_cnt, next_build_cnt, next_copy_cnt
always @(current_state) begin
    case(current_state)
        S_COUNT: begin
            next_load_cnt <= 0;
            next_find_cnt <= 0;
            count_cnt <= 0;
        end
        S_PREFIX_SUM: begin
            next_find_cnt <= 0;
            count_cnt <= prefix_cnt;
        end
        S_BUILD_OUTPUT: begin
            next_build_cnt <= 0;
        end
        S_COPY_OUTPUT: begin
            next_copy_cnt <= 0;
        end
    end
end

