output.rtl/soundgenerator.sv:
module soundgenerator #(
	parameter  CLOCK_HZ = 10_000_000
)(
	input wire clk,                                         //input clock signal with frequency 10Mhz
	input wire nrst,                                        //active low asynchronous reset.

	input wire start,                                       //indicate the start of the operation.
	input wire finish,                                      //indicate the end of operation.
	input wire [15:0] sond_dur_ms_i,                        //this signal indicate for how much time the sound should be generated in millisecond.
	input wire [15:0] half_period_us_i,                     //this signal indicate the frequency of the output signal by giving the half time period required for the output soundwave_o 

	output wire soundwave_o,                                //output sound wave signal.
	output wire busy,                                       //indicate the system is busy.
	output wire done                                        //indicate the operation is completed.
);

// TickMilli module
module TickMilli(
	input wire clk,
	input wire nrst,
	output reg tick
);
	reg [31:0] counter = 0;
	always @(posedge clk or posedge nrst) begin
		if (nrst)
			counter <= 0;
		else
			counter <= counter + 1;
		tick <= (counter == 1'b100000000);
	end
endmodule

// tickmicro module
module tickmicro(
	input wire clk,
	input wire nrst,
	output reg tick
);
	reg [31:0] counter = 0;
	always @(posedge clk or posedge nrst) begin
		if (nrst)
			counter <= 0;
		else
			counter <= counter + 1;
		tick <= (counter == 1'b1);
	end
endmodule

// Duration Timer
reg [15:0] duration_counter = 0;
wire strobe_active = 1'b0;

always @(posedge clk or posedge nrst) begin
	if (nrst)
		duration_counter <= 16'b0;
	else if (start)
		duration_counter <= sond_dur_ms_i;
	else
		duration_counter <= duration_counter - 1'b1;
	if (duration_counter == 0)
		strobe_active <= 1'b1;
end

// Busy and Done logic
reg busy = 1'b0;
reg done = 1'b0;

always @(posedge clk or posedge nrst) begin
	if (nrst)
		busy <= 1'b0;
	else if (start && !done)
		busy <= 1'b1;
	if (busy && !finish)
		done <= 1'b0;
	else if (busy && finish)
		done <= 1'b1;
end

// Soundwave signal generation
wire halfperiod_counter = 0;
wire strobe_enable = enable;

always @(posedge clk or posedge nrst) begin
	if (nrst)
		halfperiod_counter <= 16'b0;
	else if (strobe_enable)
		halfperiod_counter <= half_period_us_i;
	else
		halfperiod_counter <= halfperiod_counter - 1'b1;
	if (halfperiod_counter == 0)
		strobe_o <= ~strobe_o;
end

// Integration of TickMilli, tickmicro, Duration Timer, and Soundwave signal generation
always @(posedge clk or posedge nrst) begin
	if (nrst)
		soundwave_o <= 1'b0;
	else if (strobe_enable && busy)
		soundwave_o <= strobe_o;
end

endmodule

module strob_gen #(
	parameter	CLOCK_HZ	= 10_000_000,
	parameter	PERIOD_US	= 100
)(
	input wire  clk,
	input wire  nrst,
	input wire  enable,
	output reg  strobe_o
);

// Calculate DELAY
parameter DELAY = CLOCK_HZ * (1000000000 / CLOCK_HZ) / PERIOD_US;

// Instantiate TickMilli and tickmicro modules
TickMilli tmm(clk, nrst, strobe_o);
tickmicro tm(clk, nrst, strobe_o);

// Counter and control logic
reg [31:0] counter = 0;

always @(posedge clk or posedge nrst) begin
	if (nrst)
		counter <= DELAY;
	else if (enable)
		counter <= counter - 1'b1;
	if (counter == 0)
		strobe_o <= ~strobe_o;
end

endmodule

output.rtl/sprite_fsm.sv:
module sprite_controller_fsm#(
   parameter MEM_ADDR_WIDTH = 16,
   parameter PIXEL_WIDTH = 24,
   parameter SPRITE_WIDTH = 16,
   parameter SPRITE_HEIGHT = 16,
   parameter WAIT_WIDTH    = 4,
   parameter N_ROM         = 256
)(
   input  logic clk,
   input  logic rst_n,
   input  logic [WAIT_WIDTH-1:0] i_wait,
   output logic rw,                             
   output logic [MEM_ADDR_WIDTH-1:0] write_addr,
   output logic [PIXEL_WIDTH-1:0] write_data,   
   output logic [SPRITE_WIDTH-1:0] x_pos,       
   output logic [SPRITE_HEIGHT-1:0] y_pos,      
   input  logic [PIXEL_WIDTH-1:0] pixel_out,    
   output logic done                            
);

 typedef enum logic [2:0] {
       IDLE,
       INIT_WRITE,
       WRITE,
       INIT_READ,
       READ,
       WAIT,
       DONE
   } state_t;

   state_t current_state, next_state;

   logic [MEM_ADDR_WIDTH-1:0] addr_counter; 
   logic [PIXEL_WIDTH-1:0] data_counter;    
   logic [WAIT_WIDTH-1:0] wait_counter;     

   always @(posedge clk) begin
       if (rst_n) begin
           current_state <= IDLE;
           addr_counter <= 0;
           data_counter <= 0;
           wait_counter <= 0;
           rw <= 0;
           write_addr <= 0;
           write_data <= 24'hFF0000;
           done <= 0;
       end else begin
           case (current_state)
               IDLE: begin
                   if (!rst_n)
                       current_state <= INIT_WRITE;
                   rw <= 0;
               end
               INIT_WRITE: begin
                   addr_counter <= 0;
                   data_counter <= 0;
                   write_data <= 24'hFF0000;
                   rw <= 1;
                   next_state <= WRITE;
               end
               WRITE: begin
                   write_addr <= addr_counter;
                   write_data <= data_counter;
                   addr_counter <= addr_counter + 1;
                   data_counter <= data_counter + 1;
                   if (addr_counter == N_ROM - 1)
                       next_state <= INIT_READ;
                   else
                       next_state <= WRITE;
               end
               INIT_READ: begin
                   addr_counter <= 0;
                   rw <= 0;
                   next_state <= READ;
               end
               READ: begin
                   write_addr <= addr_counter;
                   x_pos <= addr_counter % SPRITE_WIDTH;
                   y_pos <= (addr_counter / SPRITE_WIDTH);
                   data_counter <= 0;
                   rw <= 0;
                   wait_counter <= 0;
                   done <= 0;
                   if (addr_counter == N_ROM - 1)
                       next_state <= WAIT;
                   else
                       next_state <= READ;
               end
               WAIT: begin
                   wait_counter <= wait_counter + 1;
                   if (wait_counter == i_wait)
                       next_state <= DONE;
               end
               DONE: begin
                   rw <= 0;
                   done <= 1;
                   next_state <= IDLE;
               end
           endcase
       end
   end

endmodule

