module square_root #(parameter WIDTH = 16) (
    input  wire [WIDTH-1:0] num,       
    output reg  [WIDTH/2-1:0] root     
);
    reg [WIDTH-1:0] remainder,square;         
    reg [WIDTH/2-1:0] test_bit, temp_square;        
    integer i,j;

    always @(*) 
    begin
        remainder = num;               
        root = 0;                      
        temp_square = 0;


        for (i = WIDTH/2-1; i >= 0; i = i - 1) 
        begin
            test_bit = 1'b1 << i;      
            temp_square = (root | test_bit);        
            square = 0; 
            for (j = 0; j < WIDTH; j = j + 1) 
            begin
              if (temp_square[j]) 
              begin 
                  square = square + (temp_square << j); 
              end 
            end

            if (square <= remainder) 
            begin
                root = root | test_bit; 
            end
        end
    end
endmodule

output.rtl/square_root_seq.sv:
module square_root_seq #(parameter WIDTH = 16) (
    input  wire [WIDTH-1:0] num,
    output reg  [WIDTH/2-1:0] final_root,
    input  wire clk,
    input  wire rst,
    input  wire start,
    output reg done
);

    reg [WIDTH-1:0] remainder, odd;
    reg [WIDTH/2-1:0] square_root;
    reg [2:0] state;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= 0;
            remainder <= num;
            odd <= 1;
            square_root <= 0;
            done <= 0;
        end else begin
            case (state)
                0: begin
                    if (start) begin
                        state <= 1;
                        remainder <= num;
                        odd <= 1;
                        square_root <= 0;
                        done <= 0;
                    end else
                        state <= 0;
                end
                1: begin
                    if (remainder >= odd) begin
                        remainder <= remainder - odd;
                        square_root <= square_root + 1;
                        odd <= odd + 2;
                        state <= 1;
                    end else begin
                        final_root <= square_root;
                        done <= 1;
                        state <= 0;
                    end
                end
            endcase
        end
    end

endmodule

output.rtl/static_branch_predict.sv:
module static_branch_predict(
    input [31:0] fetch_rdata_i,
    input [31:0] fetch_pc_i,
    input fetch_valid_i,
    output reg [1:0] predict_branch_taken_o,
    output [31:0] predict_branch_pc_o
);

    reg [31:0] imm_j_type, imm_b_type, imm_cj_type, imm_cb_type;
    reg instr, instr_j, instr_b, instr_cj, instr_cb;
    reg instr_b_taken;

    // Instruction type decoding
    always @(posedge fetch_valid_i) begin
        imm_j_type = (fetch_rdata_i == OPCODE_JAL) ? fetch_rdata_i : 32'h0;
        imm_b_type = (fetch_rdata_i == OPCODE_BXXX) ? fetch_rdata_i : 32'h0;
        imm_cj_type = (fetch_rdata_i == OPCODE_CJ) ? fetch_rdata_i : 32'h0;
        imm_cb_type = (fetch_rdata_i == OPCODE_CJAL) ? fetch_rdata_i : 32'h0;

        instr = fetch_rdata_i;
        instr_j = (fetch_rdata_i == OPCODE_JAL) ? 1'b1 : 1'b0;
        instr_b = (fetch_rdata_i == OPCODE_BXXX) ? 1'b1 : 1'b0;
        instr_cj = (fetch_rdata_i == OPCODE_CJ) ? 1'b1 : 1'b0;
        instr_cb = (fetch_rdata_i == OPCODE_CJAL) ? 1'b1 : 1'b0;
    end

    // Sign extension
    assign imm_j_type = {8'b{fetch_rdata_i[7:0]}, fetch_rdata_i[7:0]};
    assign imm_b_type = {8'b{fetch_rdata_i[12]}, fetch_rdata_i[12:1], 1'b0};
    assign imm_cj_type = {12'b{fetch_rdata_i[15:4], fetch_rdata_i[15], fetch_rdata_i[14:0]}, fetch_rdata_i[14]};
    assign imm_cb_type = {12'b{fetch_rdata_i[15:4], fetch_rdata_i[15], fetch_rdata_i[14:0]}, fetch_rdata_i[14]};

    // Branch or jump prediction logic
    always @(posedge fetch_valid_i) begin
        // Jumps are always predicted as taken
        if (instr_j || instr_cj) begin
            predict_branch_taken_o = 1'b1;
            predict_branch_pc_o = fetch_pc_i + imm_j_type;
        end else if (instr_b) begin
            // Branches are predicted based on the sign of the offset
            instr_b_taken = (imm_b_type[31] == 1'b1);
            predict_branch_taken_o = instr_b_taken;
            predict_branch_pc_o = fetch_pc_i + imm_b_type;
        end else
            predict_branch_taken_o = 1'b0;
    end

endmodule

// Constants
localparam OPCODE_JAL = 7'h6F;
localparam OPCODE_BXXX = 7'h63;
localparam OPCODE_CJ = 7'h6C;
localparam OPCODE_CJAL = 7'h67;

// Example usage
static_branch_predict instance_name(
    .fetch_rdata_i(fetch_rdata_i),
    .fetch_pc_i(fetch_pc_i),
    .fetch_valid_i(fetch_valid_i),
    .predict_branch_taken_o(predict_branch_taken_o),
    .predict_branch_pc_o(predict_branch_pc_o)
);

// End of module
 module static_branch_predict(
    input [31:0] fetch_rdata_i,
    input [31:0] fetch_pc_i,
    input fetch_valid_i,
    output reg [1:0] predict_branch_taken_o,
    output [31:0] predict_branch_pc_o
);

    // Instruction type decoding
    always @(posedge fetch_valid_i) begin
        // Uncompressed jump instructions
        if (fetch_rdata_i == OPCODE_JAL || fetch_rdata_i == OPCODE_JALR) begin
            imm_j_type = fetch_rdata_i;
        end else if (fetch_rdata_i == OPCODE_BXXX) begin
            imm_b_type = {19{fetch_rdata_i[12]}, fetch_rdata_i[12:1], 1'b0};
        end else if (fetch_rdata_i == OPCODE_CJ || fetch_rdata_i == OPCODE_CJAL) begin
            imm_cj_type = {12'b{fetch_rdata_i[15:4], fetch_rdata_i[15], fetch_rdata_i[14:0]}, fetch_rdata_i[14]};
        end
        // Other instructions are not supported
        imm_cb_type = 32'h0;
        instr = fetch_rdata_i;
        instr_j = (fetch_rdata_i == OPCODE_JAL || fetch_rdata_i == OPCODE_JALR) ? 1'b1 : 1'b0;
        instr_b = (fetch_rdata_i == OPCODE_BXXX) ? 1'b1 : 1'b0;
        instr_cj = (fetch_rdata_i == OPCODE_CJ || fetch_rdata_i == OPCODE_CJAL) ? 1'b1 : 1'b0;
        instr_cb = 1'b0;
    end

    // Sign extension
    assign imm_j_type = {8'b{fetch_rdata_i[7:0]}, fetch_rdata_i[7:0]};
    assign imm_b_type = {8'b{fetch_rdata_i[12]}, fetch_rdata_i[12:1], 1'b0};
    assign imm_cj_type = {12'b{fetch_rdata_i[15:4], fetch_rdata_i[15], fetch_rdata_i[14:0]}, fetch_rdata_i[14]};

    // Branch or jump prediction logic
    always @(posedge fetch_valid_i) begin
        // Jumps are always predicted as taken
        if (instr_j || instr_cj) begin
            predict_branch_taken_o = 1'b1;
            predict_branch_pc_o = fetch_pc_i + imm_j_type;
        // Branches are predicted based on the sign of the offset
        } else if (instr_b) begin
            predict_branch_taken_o = (imm_b_type[31] == 1'b1);
            predict_branch_pc_o = fetch_pc_i + imm_b_type;
        end else
            predict_branch_taken_o = 1'b0;
    end

endmodule

input.rtl/static_branch_predict.sv:
module static_branch_predict (

  // Instruction from fetch stage
  input  logic [31:0] fetch_rdata_i,
  input  logic [31:0] fetch_pc_i,
  input  logic [31:0] register_addr_i,
  input  logic        fetch_valid_i,

  // Prediction for supplied instruction
  output logic        predict_branch_taken_o,
  output logic [31:0] predict_branch_pc_o
);
  logic [31:0] reg_addr;
  logic [31:0] imm_jal_type;
  logic [31:0] imm_jalr_type;
  logic [31:0] imm_b_type;
  logic [31:0] imm_cj_type;
  logic [31:0] imm_cb_type;

  logic [31:0] branch_imm;

  logic [31:0] instr;

  logic instr_jal;
  logic instr_jalr;
  logic instr_b;
  logic instr_cj;
  logic instr_cb;

  logic instr_b_taken;


  localparam OPCODE_BRANCH = 7'h63;
  localparam OPCODE_JAL    = 7'h6F;
  localparam OPCODE_JALR   = 7'h67;

  assign instr = fetch_rdata_i;
  assign reg_addr = register_addr_i;

  assign imm_jal_type = {{12{instr[31]}}, instr[19:12], instr[20], instr[30:21], 1'b0 };
  assign imm_jalr_type = {{20{instr[31]}}, instr[31:20]}+reg_addr;
  assign imm_b_type = { {19{instr[31]}}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0 };

  assign imm_cj_type = { {20{instr[12]}}, instr[12], instr[8], instr[10:9], instr[6], instr[7],
    instr[2], instr[11], instr[5:3], 1'b0 };

  assign imm_cb_type = { {23{instr[12]}}, instr[12], instr[6:5], instr[2], instr[11:10],
    instr[4:3], 1'b0};

  assign instr_b    = instr[6:0] == OPCODE_BRANCH;
  assign instr_jal  = instr[6:0] == OPCODE_JAL;
  assign instr_jalr = instr[6:0] == OPCODE_JALR;

  assign instr_cb = (instr[1:0] == 2'b01) & ((instr[15:13] == 3'b110) | (instr[15:13] == 3'b111));
  assign instr_cj = (instr[1:0] == 2'b01) & ((instr[15:13] == 3'b101) | (instr[15:13] == 3'b001));

  always_comb begin
    branch_imm = imm_b_type;

    case(1'b1)
      instr_jal  : branch_imm = imm_jal_type;
      instr_jalr : branch_imm = imm_jalr_type;
      instr_b    : branch_imm = imm_b_type;
      instr_cj   : branch_imm = imm_cj_type;
      instr_cb   : branch_imm = imm_cb_type;
      default    : ;
    endcase
  end
  assign predict_branch_pc_o    = fetch_pc_i + branch_imm; 
  assign instr_b_taken = (instr_b & imm_b_type[31]) | (instr_cb & imm_cb_type[31]);
  assign predict_branch_taken_o = fetch_valid_i & (instr_jal | instr_jalr | instr_cj | instr_b_taken);

endmodule

output.rtl/static_branch_predict.sv:
module static_branch_predict (

  // Instruction from fetch stage
  input  logic [31:0] fetch_rdata_i,
  input  logic [31:0] fetch_pc_i,
  input  logic [31:0] register_addr_i,
  input  logic        fetch_valid_i,

  // Prediction outputs
  output logic        predict_branch_taken_o,
  output logic [31:0] predict_branch_pc_o,
  output logic [7:0] predict_confidence_o,
  output logic        predict_exception_o,
  output logic [3:0] predict_branch_type_o
);
  logic [31:0] imm_b_type;
  logic [31:0] imm_jal_type;
  logic [31:0] imm_jalr_type;
  logic [31:0] imm_cj_type;
  logic [31:0] imm_cb_type;

  logic instr_jal;
  logic instr_jalr;
  logic instr_b;
  logic instr_cj;
  logic instr_cb;

  localparam OPCODE_BRANCH = 7'h63;
  localparam OPCODE_JAL    = 7'h6F;
  localparam OPCODE_JALR   = 7'h67;

  assign imm_jal_type = {{12{fetch_rdata_i}},fetch_rdata_i[19:12],fetch_rdata_i[20],fetch_rdata_i[30:21],1'b0 };
  assign imm_jalr_type = {{20{fetch_rdata_i}},fetch_rdata_i[31:20]+register_addr_i;
  assign imm_b_type = { {19{fetch_rdata_i}},fetch_rdata_i[31],fetch_rdata_i[7],fetch_rdata_i[30:25],fetch_rdata_i[11:8],1'b0 };
  assign imm_cj_type = { {20{fetch_rdata_i}},fetch_rdata_i[12],fetch_rdata_i[8],fetch_rdata_i[10:9],fetch_rdata_i[6],fetch_rdata_i[7],
    fetch_rdata_i[2],fetch_rdata_i[11],fetch_rdata_i[5:3],1'b0 };
  assign imm_cb_type = { {23{fetch_rdata_i}},fetch_rdata_i[12],fetch_rdata_i[6],fetch_rdata_i[2],fetch_rdata_i[11:10],
    fetch_rdata_i[4:3],1'b0};

  assign instr = fetch_rdata_i;
  assign instr_jal  = instr[6:0] == OPCODE_JAL;
  assign instr_jalr = instr[6:0] == OPCODE_JALR;

  assign instr_b    = instr[6:0] == OPCODE_BRANCH;
  assign instr_cb   = (instr[1:0] == 2'b01) & ((instr[15:13] == 3'b110) | (instr[15:13] == 3'b111));
  assign instr_cj = (instr[1:0] == 2'b01) & ((instr[15:13] == 3'b101) | (instr[15:13] == 3'b001));

  always_comb begin
    case(instr[6:0])
      OPCODE_BRANCH : begin
        if (imm_b_type[31] == 1)
          predict_branch_taken_o = 1; // Backward branch, high probability
        else
          predict_branch_taken_o = instr_b & imm_b_type[31]; // Forward branch, 50% probability
      end
      OPCODE_JAL    : begin
        predict_branch_taken_o = 1; // Jump instruction, 100% probability
      end
      OPCODE_JALR   : begin
        predict_branch_taken_o = 1; // JALR instruction, 100% probability
      end
      default     : begin
        predict_branch_taken_o = fetch_valid_i & (instr_jal | instr_jalr | instr_cj | instr_b_taken);
      end
    endcase

    assign predict_branch_pc_o    = fetch_pc_i + imm_b_type;
    assign predict_confidence_o = (predict_branch_taken_o ? 8'd90 : 8'd50); // Higher confidence for backward branches
    assign predict_exception_o = (fetch_pc_i[1:0] != 2'b00);
    assign predict_branch_type_o = (instr[6:0] == OPCODE_BRANCH) ? 3'b011 :
                                 (instr[6:0] == OPCODE_JAL) ? 3'b001 :
                                 (instr[6:0] == OPCODE_JALR) ? 3'b010 : 3'b000;
  end

  assign imm_b_type = { {19{fetch_rdata_i}},fetch_rdata_i[31],fetch_rdata_i[7],fetch_rdata_i[30:25],fetch_rdata_i[11:8],1'b0 };

  assign branch_imm = imm_b_type;

  assign instr_b_taken = (instr_b & imm_b_type[31]) | (instr_cb & imm_cb_type[31]);

  // Target Address Calculation
  assign predict_branch_pc_o    = fetch_pc_i + branch_imm; 
endmodule

always @(*) begin
  instr = fetch_rdata_i;
  reg_addr = register_addr_i;

  // Instruction type decoding
  instr_jal = (instr[6:0] == 7'h6F);
  instr_jalr = (instr[6:0] == 7'h67);
  instr_b = (instr[6:0] == 7'h63);
  instr_cj = (instr[10:8] == 7'h00 && instr[6:0] == 7'h01); // Assuming CJ is indicated by 0x01 in the upper bits
  instr_cb = (instr[10:8] == 7'h00 && instr[6:0] == 7'h02); // Assuming CB is indicated by 0x02 in the upper bits

  // Branch immediate selection
  branch_imm = instr_jal ? imm_jal_type :
               instr_jalr ? imm_jalr_type :
               instr_b ? imm_b_type :
               instr_cj ? imm_cj_type :
               imm_cb_type;

  // Branch taken decision for B-type branches
  instr_b_taken = instr_b && (imm_b_type[31] == 1);

  // Branch prediction
  predict_branch_taken_o = instr_jal || instr_jalr || instr_b || instr_cj || instr_cb;

  // Branch target address calculation
  predict_branch_pc_o = fetch_pc_i + branch_imm;
end

module static_branch_predict(
  // Instruction from fetch stage
  input  logic [31:0] fetch_rdata_i,
  input  logic [31:0] fetch_pc_i,
  input  logic [31:0] register_addr_i,
  input  logic        fetch_valid_i,

  // Prediction for supplied instruction
  output logic        predict_branch_taken_o,
  output logic [31:0] predict_branch_pc_o,

  // Additional outputs
  output logic [7:0]  predict_confidence_o,   // Confidence level in prediction
  output logic        predict_exception_o,    // Exception/misalignment detection
  output logic [2:0]  predict_branch_type_o,  // Type of branch
  output logic [31:0] predict_branch_offset_o // Calculated branch offset
);

  logic [31:0] reg_addr;
  logic [31:0] imm_jal_type;
  logic [31:0] imm_jalr_type;
  logic [31:0] imm_b_type;
  logic [31:0] imm_cj_type;
  logic [31:0] imm_cb_type;
  logic [31:0] instr;

  logic instr_jal;
  logic instr_jalr;
  logic instr_b;
  logic instr_cj;
  logic instr_cb;

  logic instr_b_taken;

  // Instruction decoding
  always_comb begin
    instr = fetch_rdata_i;

    instr_jal = (instr[6:0] == 7'h6F);
    instr_jalr = (instr[6:0] == 7'h67);
    instr_b = (instr[6:0] == 7'h63);
    instr_cj = (instr[21:16] == 7'h00000000); // Example condition for CJ, replace with actual CJ decoding logic
    instr_cb = (instr[21:16] == 7'h00000000); // Example condition for CB, replace with actual CB decoding logic

    // Offset calculation
    if (instr_jal) begin
      imm_jal_type = { {12{instr[31]}}, instr[19:12], instr[20], instr[30:21], 1'b0 };
    end
    else if (instr_jalr) begin
      imm_jalr_type = {{20{instr[31]}}, instr[31:20]} + register_addr_i;
    end
    else if (instr_b) begin
      imm_b_type =  { {19{instr[31]}}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0 };
    end
    else if (instr_cj) begin
      imm_cj_type = { {20{instr[12]}}, instr[12], instr[8], instr[10:9], instr[6], instr[7], instr[2], instr[11], instr[5:3], 1'b0 };
    end
    else if (instr_cb) begin
      imm_cb_type = { {23{instr[12]}}, instr[12], instr[6:5], instr[2], instr[11:10], instr[4:3], 1'b0 };
    end
    else begin
      imm_jal_type = 32'b0;
      imm_jalr_type = 12'b0;
      imm_b_type = 32'b0;
      imm_cj_type = 32'b0;
      imm_cb_type = 32'b0;
    end

    // Branch prediction logic
    predict_branch_taken_o = (instr_b_taken && instr_b) || instr_jal || instr_jalr || instr_cj || instr_cb;

    // Confidence level calculation
    if (instr_b || instr_cj || instr_cb) begin
      predict_confidence_o = 90;
    end
    else if (instr_jal || instr_jalr) begin
      predict_confidence_o = 100;
    end
    else begin
      predict_confidence_o = 0;
    end

    // Exception detection
    predict_exception_o = (fetch_pc_i % 4) != 0;

    // Branch type determination
    predict_branch_type_o = (instr_jal) ? 0 : (instr_jalr) ? 1 : (instr_b) ? 2 : (instr_cj) ? 3 : 4;

    // Branch offset calculation
    case (predict_branch_type_o)
      0: predict_branch_offset_o = imm_jal_type;
      1: predict_branch_offset_o = imm_jalr_type;
      2: predict_branch_offset_o = imm_b_type;
      3: predict_branch_offset_o = imm_cj_type;
      4: predict_branch_offset_o = imm_cb_type;
    endcase

end

