    always @(posedge clk) begin
        if (interrupt_asserted && interrupt_enable) begin
            interrupt <= 1;
        end else begin
            interrupt <= 0;
        end
    end

    // AXI Interface
    always @(posedge clk) begin
        case (axi_addr)
            3'b000: begin
                axi_rdata <= count[15:0];
            end
            3'b001: begin
                match_value <= count[15:0];
            end
            3'b010: begin
                reload_value <= count[15:0];
            end
            3'b011: begin
                control_reg <= control_reg;
            end
            3'b100: begin
                interrupt_asserted <= interrupt_asserted;
            end
