module vga_controller (
    input clk,
    input reset,
    input [7:0] color_in,
    output reg hsync,
    output reg vsync,
    output reg [7:0] red,
    output reg [7:0] green,
    output reg [7:0] blue,
    output [9:0] next_x,
    output [9:0] next_y,
    output sync,
    output clk_sync,
    output blank
);

    // State and counter definitions
    typedef enum logic [1:0] {H_ACTIVE, H_FRONT, H_PULSE, H_BACK, V_ACTIVE, V_FRONT, V_PULSE, V_BACK} h_state_t;
    typedef enum logic [1:0] {V_ACTIVE, V_FRONT, V_PULSE, V_BACK} v_state_t;
    logic [9:0] h_counter = 0;
    logic [9:0] v_counter = 0;

    // State machine for horizontal timing
    always_ff @(posedge clk) begin
        case (h_state_t)
            H_ACTIVE: begin
                h_counter <= h_counter + 1'b1;
                if (h_counter == H_ACTIVE) begin
                    h_state_t = H_FRONT;
                end
            end
            H_FRONT: begin
                if (h_counter == H_FRONT) begin
                    h_state_t = H_PULSE;
                end
            end
            H_PULSE: begin
                if (h_counter == H_PULSE) begin
                    h_state_t = H_BACK;
                end
            end
            H_BACK: begin
                if (h_counter == H_BACK) begin
                    h_state_t = H_ACTIVE;
                end
            end
        endcase
    end

    // State machine for vertical timing
    always_ff @(posedge clk) begin
        case (v_state_t)
            V_ACTIVE: begin
                v_counter <= v_counter + 1'b1;
                if (v_counter == V_ACTIVE) begin
                    v_state_t = V_FRONT;
                end
            end
            V_FRONT: begin
                if (v_counter == V_FRONT) begin
                    v_state_t = V_PULSE;
                end
            end
            V_PULSE: begin
                if (v_counter == V_PULSE) begin
                    v_state_t = V_BACK;
                end
            end
            V_BACK: begin
                if (v_counter == V_BACK) begin
                    v_state_t = V_ACTIVE;
                end
            end
        endcase
    end

    // Synchronization signals
    always_ff begin
        sync <= 1'b0;
        hsync <= 1'b0;
        vsync <= 1'b0;
        blank <= 1'b1;
    end

    // Sync pulse generation
    always_ff begin
        if (h_state_t == H_PULSE) begin
            hsync <= 1'b1;
        end else if (h_state_t == H_BACK) begin
            hsync <= 1'b0;
        end
    end

    always_ff begin
        if (v_state_t == V_PULSE) begin
            vsync <= 1'b1;
        end else if (v_state_t == V_BACK) begin
            vsync <= 1'b0;
        end
    end

    // Color output control
    always_ff begin
        if (h_state_t == H_ACTIVE) begin
            next_x <= h_counter;
            red <= color_in[7:5];
            green <= color_in[4:2];
            blue <= color_in[1:0];
        end else begin
            next_x <= 0;
            red <= 8'd0;
            green <= 8'd0;
            blue <= 8'd0;
        end
    end

    // Blanking signal control
    always_ff begin
        if (h_state_t == H_BACK || v_state_t == V_BACK) begin
            blank <= 1'b1;
        end else begin
            blank <= 1'b0;
        end
    end

    // Reset logic
    always_ff begin
        if (reset) begin
            h_counter <= 10'b0;
            v_counter <= 10'b0;
            next_x <= 10'b0;
            next_y <= 10'b0;
            sync <= 1'b0;
            hsync <= 1'b0;
            vsync <= 1'b0;
            blank <= 1'b0;
        end
    end

endmodule

module vga_controller (
    input logic clock,      // 25 MHz
    input logic reset,      // Active high
    input logic [7:0] color_in, // Pixel color data (RRRGGGBB)
    output logic [9:0] next_x,  // x-coordinate of NEXT pixel that will be drawn
    output logic [9:0] next_y,  // y-coordinate of NEXT pixel that will be drawn
    output logic hsync,     // HSYNC (to VGA connector)
    output logic vsync,     // VSYNC (to VGA connector)
    output logic [7:0] red, // RED (to resistor DAC VGA connector)
    output logic [7:0] green, // GREEN (to resistor DAC to VGA connector)
    output logic [7:0] blue, // BLUE (to resistor DAC to VGA connector)
    output logic sync,      // SYNC to VGA connector
    output logic clk,       // CLK to VGA connector
    output logic blank,      // BLANK to VGA connector
    output logic [7:0] h_state, // States of Horizontal FSM
    output logic [7:0] v_state, // States of Vertical FSM
);

    parameter logic [9:0] H_ACTIVE  =  10'd640;
    parameter logic [9:0] H_FRONT   =  10'd16;
    parameter logic [9:0] H_PULSE   =  10'd96;
    parameter logic [9:0] H_BACK    =  10'd48;
    parameter logic [9:0] V_ACTIVE  =  10'd480;
    parameter logic [9:0] V_FRONT   =  10'd10;
    parameter logic [9:0] V_PULSE   =  10'd2;
    parameter logic [9:0] V_BACK    =  10'd33;
    parameter logic LOW   = 1'b0;
    parameter logic HIGH  = 1'b1;
    parameter logic H_ACTIVE_STATE  = 8'd0;
    parameter logic H_FRONT_STATE   = 8'd1;
    parameter logic H_PULSE_STATE   = 8'd2;
    parameter logic H_BACK_STATE    = 8'd3;
    parameter logic V_ACTIVE_STATE  = 8'd0;
    parameter logic V_FRONT_STATE   = 8'd1;
    parameter logic V_PULSE_STATE   = 8'd2;
    parameter logic V_BACK_STATE    = 8'd3;

    logic line_done;
    logic [9:0] h_counter;
    logic [9:0] v_counter;

    always_ff @(posedge clock or posedge reset) begin
        if (reset) begin
            h_counter   <= 10'd0;
            v_counter   <= 10'd0;
            h_state     <= H_ACTIVE_STATE;
            v_state     <= V_ACTIVE_STATE;
            line_done   <= LOW;
        end
        else begin
            case (h_state)
                H_ACTIVE_STATE: begin
                    h_counter <= h_counter + 1;
                    if (h_counter == H_ACTIVE - 1) begin
                        h_state <= H_FRONT_STATE;
                    end
                end
                H_FRONT_STATE: begin
                    h_counter <= h_counter + 1;
                    if (h_counter == H_FRONT - 1) begin
                        h_state <= H_PULSE_STATE;
                    end
                end
                H_PULSE_STATE: begin
                    h_counter <= h_counter + 1;
                    if (h_counter == H_PULSE - 1) begin
                        h_state <= H_BACK_STATE;
                    end
                end
                H_BACK_STATE: begin
                    h_counter <= h_counter + 1;
                    if (h_counter == H_BACK - 1) begin
                        h_state <= H_ACTIVE_STATE;
                        line_done <= HIGH;
                    end
                end
            endcase

            case (v_state)
                V_ACTIVE_STATE: begin
                    v_counter <= v_counter + 1;
                    if (v_counter == V_ACTIVE - 1) begin
                        v_state <= V_FRONT_STATE;
                    end
                end
                V_FRONT_STATE: begin
                    v_counter <= v_counter + 1;
                    if (v_counter == V_FRONT - 1) begin
                        v_state <= V_PULSE_STATE;
                    end
                end
                V_PULSE_STATE: begin
                    v_counter <= v_counter + 1;
                    if (v_counter == V_PULSE - 1) begin
                        v_state <= V_BACK_STATE;
                    end
                end
                V_BACK_STATE: begin
                    v_counter <= v_counter + 1;
                    if (v_counter == V_BACK - 1) begin
                        v_state <= V_ACTIVE_STATE;
                    end
                end
            endcase

            case (h_state)
                H_ACTIVE_STATE: begin
                    red <= color_in;
                    green <= color_in;
                    blue <= color_in;
                end
                H_FRONT_STATE: begin
                    red <= HIGH;
                    green <= HIGH;
                    blue <= HIGH;
                end
                H_PULSE_STATE: begin
                    red <= HIGH;
                    green <= HIGH;
                    blue <= HIGH;
                end
                H_BACK_STATE: begin
                    red <= HIGH;
                    green <= HIGH;
                    blue <= HIGH;
                end
            endcase

            case (v_state)
                V_ACTIVE_STATE: begin
                    red <= color_in;
                    green <= color_in;
                    blue <= color_in;
                end
                V_FRONT_STATE: begin
                    red <= HIGH;
                    green <= HIGH;
                    blue <= HIGH;
                end
                V_PULSE_STATE: begin
                    red <= HIGH;
                    green <= HIGH;
                    blue <= HIGH;
                end
                V_BACK_STATE: begin
                    red <= HIGH;
                    green <= HIGH;
                    blue <= HIGH;
                end
            endcase
        end
    end

    assign clk = clock;
    assign sync = hsync ^ vsync;
    assign next_x = (h_state == H_ACTIVE_STATE) ? h_counter : 10'd0;
    assign next_y = (v_state == V_ACTIVE_STATE) ? v_counter : 10'd0;

endmodule

