output.rtl/wishbone_to_ahb_bridge.sv:
module wishbone_to_ahb_bridge(
    input wire clk_i,
    input wire rst_i,
    input wire cyc_i,
    input wire stb_i,
    input wire [3:0] sel_i,
    input wire we_i,
    input wire [31:0] addr_i,
    input wire [31:0] data_i,
    output reg ack_o,
    output reg [31:0] data_o,
    output reg [1:0] hresp,
    output reg hready,
    output reg [31:0] haddr,
    output reg [31:0] hdata,
    output reg [2:0] hsize,
    output reg hwrite,
    output reg hburst
);

    // Internal signals
    reg [31:0] wb_data;
    reg [31:0] wb_addr;
    reg [31:0] ahb_data;
    reg [31:0] ahb_addr;
    reg [2:0] hsize_reg;
    reg [2:0] hburst_reg;
    reg [1:0] htrans_reg;

    // State machine for managing transaction phases
    localparam IDLE = 0, NON_SEQUENTIAL = 1, BUSY = 2;
    reg [2:0] state, next_state;

    // Endian conversion logic
    function [31:0] convert_to_little_endian(input [31:0] data);
        return {data[31], data[30], data[29], data[28], data[27], data[26], data[25], data[24], data[23], data[22], data[21], data[20], data[19], data[18], data[17], data[16], data[15], data[14], data[13], data[12], data[11], data[10], data[9], data[8], data[7], data[6], data[5], data[4], data[3], data[2], data[1], data[0]};
    endfunction

    function [31:0] convert_to_big_endian(input [31:0] data);
        return {data[0], data[1], data[2], data[3], data[4], data[5], data[6], data[7], data[8], data[9], data[10], data[11], data[12], data[13], data[14], data[15], data[16], data[17], data[18], data[19], data[20], data[21], data[22], data[23], data[24], data[25], data[26], data[27], data[28], data[29], data[30], data[31]};
    endfunction

    // FSM implementation
    always @(posedge clk_i or posedge rst_i) begin
        if (rst_i) begin
            state <= IDLE;
            wb_data <= 0;
            wb_addr <= 0;
            ahb_data <= 0;
            ahb_addr <= 0;
            ack_o <= 0;
            hready <= 0;
            hwrite <= 0;
            hburst <= 3'b000;
            hsize_reg <= 3'b000;
            haddr_reg <= 0;
            hdata_reg <= 0;
            hresp_reg <= 0;
        end else begin
            case (state)
                IDLE: begin
                    if (cyc_i && stb_i) begin
                        wb_addr <= addr_i;
                        wb_data <= data_i;
                        state <= NON_SEQUENTIAL;
                    end
                end
                NON_SEQUENTIAL: begin
                    wb_data <= convert_to_big_endian(wb_data);
                    wb_addr <= convert_to_big_endian(wb_addr);
                    ahb_addr <= convert_to_little_endian(wb_addr) & (sel_i << 5);
                    ahb_data <= convert_to_little_endian(wb_data) & (sel_i << (32 - sel_i));
                    state <= BUSY;
                end
                BUSY: begin
                    if (we_i) begin
                        ahb_data <= ahb_data;
                        ahb_addr <= ahb_addr;
                        hwrite <= 1;
                        hsize_reg <= hsize;
                        hburst_reg <= hburst;
                        haddr_reg <= ahb_addr;
                        hdata_reg <= ahb_data;
                        hresp_reg <= 0;
                        hready <= 1;
                    end else begin
                        hwrite <= 0;
                        hresp_reg <= 1;
                    end
                    state <= NON_SEQUENTIAL;
                end
            endcase
        end
    end

    // Output logic
    assign data_o = convert_to_little_endian(ahb_data);
    assign ack_o = hresp_reg;
    assign haddr = ahb_addr;
    assign hdata = ahb_data;
    assign hsize = hsize_reg;
    assign hburst = hburst_reg;
    assign hwrite = hwrite;
    assign hready = hready;

endmodule

output.rtl/Word_Change_Pulse.sv:
module Word_Change_Pulse#(
    parameter DATA_WIDTH = 8 // Default word width
) (
    input  wire                  clk,               // Clock signal for synchronizing operations
    input  wire                  reset,             // Reset signal to initialize the module
    input  wire [DATA_WIDTH-1:0] data_in,           // Input data, width defined by parameter DATA_WIDTH
    input  wire [DATA_WIDTH-1:0] mask,              // Mask signal to enable/disable change detection for each bit
    input  wire [DATA_WIDTH-1:0] match_pattern,     // Pattern to match for generating the pulse
    input  wire                  enable,            // Enable signal to allow module operation
    input  wire                  latch_pattern,     // Signal to latch the match pattern
    output reg                   word_change_pulse, // Output signal indicating a change in any bit of data_in
    output reg                   pattern_match_pulse, // Output signal indicating a match with the pattern
    output reg [DATA_WIDTH-1:0]  latched_pattern    // Latched pattern for comparison
);

    wire [DATA_WIDTH-1:0] change_pulses;

    reg [DATA_WIDTH-1:0] masked_data_in;
    reg [DATA_WIDTH-1:0] masked_change_pulses;
    reg match_detected;

    genvar i;

    // Instantiate Bit_Change_Detector modules
    generate
        for (i = 0; i < DATA_WIDTH; i++) begin
            if (mask[i]) begin
                Bit_Change_Detector bit_detector_inst(
                    .clk(clk),
                    .reset(reset),
                    .bit_in(data_in[i]),
                    .change_pulse(masked_change_pulses[i])
                );
            end
        end
    endgenerate

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            masked_data_in <= {DATA_WIDTH{1'b0}};
            masked_change_pulses <= {DATA_WIDTH{1'b0}};
            word_change_pulse <= 1'b0;
            match_detected <= 1'b0;
            pattern_match_pulse <= 1'b0;
            latched_pattern <= {DATA_WIDTH{1'b0}};
        end else if (enable) begin
            // Latch pattern if latch_pattern is asserted
            if (latch_pattern) begin
                latched_pattern <= match_pattern;
            end
            // Mask data_in and detect changes
            masked_data_in = data_in & mask;
            masked_change_pulses = masked_data_in ^ masked_change_pulses;
            word_change_pulse = (masked_change_pulses != {DATA_WIDTH{1'b0}}) | (word_change_pulse & ~mask);
            // Compare masked data_in with latched_pattern & mask for pattern_match_pulse
            match_detected = (masked_data_in == latched_pattern) | (match_detected & ~mask);
            pattern_match_pulse = match_detected | (pattern_match_pulse & ~mask);
        end else begin
            // Handle the case when 'enable' is low
            word_change_pulse <= 1'b0;
            pattern_match_pulse <= 1'b0;
        end
    end

endmodule

module Bit_Change_Detector (
   input  wire clk,          // Clock signal
    input  wire reset,       // Reset signal to initialize the module
    input  wire bit_in,      // Single bit input to detect changes
    output reg  change_pulse // Pulse signal indicating a change in the input bit
);

    reg bit_in_d;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            bit_in_d <= 1'b0;
            change_pulse <= 1'b0;
        end else begin
            bit_in_d <= bit_in;
            change_pulse <= (bit_in_d != bit_in) | (change_pulse & ~bit_in);
        end
    end
endmodule

